insert into kitchens (id, name) values ('11111111-1111-4111-8111-111111111111', 'My Kitchen')
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Schweizerhof Brioche', 'Yield: 2 loaves', 'Bakery & Bread', 'Medium', '2 loaves', '35 min', '1.9 hr', NULL, NULL, '[{"type": "table", "rows": [["Water", "600 ml"], ["Milk", "300 ml"], ["Grapeseed oil", "220 ml"], ["Butter, soft", "146 g"], ["Flour", "1500 g"], ["Salt", "44 g"], ["Sugar", "60 g"], ["Fresh yeast", "60 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all ingredients in a stand mixer bowl.", "Mix/knead on speed 2 for 16 minutes, then increase to speed 2.5 for a further 10 minutes, until the dough is smooth, elastic, and pulls cleanly from the sides of the bowl.", "Split the dough evenly into 2 loaf pans.", "Cover with a damp towel and rest/proof for 115 minutes.", "Egg wash the tops before baking.", "Preheat the oven for 5 minutes at 190°C.", "Bake for 10 minutes at 190°C, then — without opening the oven door — reduce the temperature to 170°C and continue baking for 35 minutes.", "Cool on a wire rack before slicing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Butterhead Lettuce, Wild Herbs, Croutons, Dijon Vinaigrette', NULL, 'Salads & Starters', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Salad", "rows": [["Butterhead lettuce heart", "1/2"], ["Wild herbs", "10 g"], ["Croutons", "15 g"], ["Dijon vinaigrette", "50 ml"]]}, {"type": "table", "heading": "Dijon Dressing", "rows": [["Dijon mustard", "100 g"], ["Dijon mustard (coarse)", "50 g"], ["White wine vinegar", "150 g"], ["Vegetable stock, reduced", "100 ml"], ["Rapeseed oil", "500 ml"], ["Olive oil", "100 ml"], ["Shallots (fine brunoise)", "30 g"], ["Acacia honey", "20 g"], ["Umami seasoning, Tabasco, salt, pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Make the Dijon dressing: whisk both mustards with white wine vinegar and reduced vegetable stock.", "Slowly whisk in the rapeseed and olive oil to emulsify, then stir in shallots and acacia honey.", "Season with umami seasoning, Tabasco, salt, and pepper to taste.", "Tear the butterhead lettuce heart into leaves, toss gently with wild herbs and croutons.", "Dress lightly just before serving so the leaves stay crisp — extra dressing on the side."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Burrata, Inca Tomatoes, Grilled Peach, Spiced Honey', NULL, 'Salads & Starters', 'Easy', NULL, NULL, '30 min', NULL, NULL, '[{"type": "table", "heading": "Plate", "rows": [["Mini burrata", "50 g"], ["Inca (physalis) tomatoes", "150 g"], ["Olive oil", "10 g"], ["White balsamic", "5 g"], ["Grilled peach", "50 g"], ["Herb salad", "25 g"]]}, {"type": "table", "heading": "Spiced Honey", "rows": [["Liquid honey", "150 g"], ["Red chilli, deseeded", "1"], ["Thyme sprigs", "3"], ["Coriander seed", "3 g"]]}, {"type": "steps", "heading": "Method", "items": ["Spiced honey: warm the honey gently with the deseeded red chilli, thyme sprigs, and coriander seed. Infuse off the heat for 20–30 minutes, then strain.", "Halve the peach, brush with a little oil, and grill or char on a hot pan until lightly caramelized with grill marks.", "Toss the Inca tomatoes with olive oil and white balsamic, season lightly.", "Plate the burrata in the centre, scatter the dressed tomatoes and grilled peach around it.", "Finish with a drizzle of the spiced honey and the herb salad."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Celery, Apple & Roasted Walnut Salad with Roquefort Dressing', NULL, 'Salads & Starters', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Salad", "rows": [["Radicchio leaves", "2"], ["Celery stalk", "75 g"], ["Granny Smith apple", "75 g"], ["Caramelized walnuts", "20 g"]]}, {"type": "table", "heading": "Roquefort Dressing", "rows": [["Roquefort AOC", "150 g"], ["Crème fraîche", "100 g"], ["Buttermilk", "50 ml"], ["White balsamic", "20 ml"], ["Vegetable stock", "to loosen"], ["Pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Roquefort dressing: blend the Roquefort with crème fraîche and buttermilk until smooth but still with some texture.", "Loosen with white balsamic and a little vegetable stock to a pourable consistency; season with pepper (the cheese usually provides enough salt).", "Thinly slice the celery on the bias, and slice the apple into fine matchsticks or thin wedges just before serving to prevent browning.", "Toss celery, apple, and radicchio leaves together, season lightly.", "Plate, scatter over the caramelized walnuts, and finish with the Roquefort dressing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Wagyu Steak Salad, Avocado, Crispy Onion, Chimichurri', NULL, 'Salads & Starters', 'Easy', NULL, NULL, '5 min', NULL, NULL, '[{"type": "table", "heading": "Plate", "rows": [["Wagyu steak", "90 g"], ["Avocado, ripe", "60 g"], ["Baby spinach / wild herbs", "20 g"], ["Chimichurri", "30 g"], ["Crispy onion", "15 g"], ["Radish", "10 g"], ["Lime dressing", "30 ml"]]}, {"type": "table", "heading": "Lime Dressing", "rows": [["Rapeseed oil", "430 ml"], ["Rice vinegar", "285 ml"], ["Lime juice", "145 ml"], ["Liquid honey", "85 g"], ["Light soy sauce", "55 ml"], ["Lime zest", "from 3 limes"]]}, {"type": "steps", "heading": "Method", "items": ["Lime dressing: whisk rapeseed oil, rice vinegar, lime juice, honey, soy sauce, and lime zest together until emulsified.", "Season the wagyu steak, sear hard and fast on a very hot pan or grill for a rare-to-medium-rare centre. Rest 5 minutes, then slice thinly against the grain.", "Toss the baby spinach/wild herbs with a little lime dressing.", "Arrange the dressed greens on the plate, fan the sliced wagyu over the top.", "Add sliced avocado and radish, spoon over the chimichurri, scatter with crispy onion.", "Finish with a final drizzle of lime dressing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Grilled Octopus, Peppers, Garlic, Sherry', NULL, 'Salads & Starters', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Plate", "rows": [["Octopus, grilled", "120 g"], ["Red peppers, braised", "80 g"], ["Fennel shavings", "40 g"], ["Garlic, roasted", "4 g"], ["Lemon zest", "to taste"], ["Taggiasca olives", "10 g"], ["Flat-leaf parsley, julienne", "to taste"], ["Mint, julienne", "to taste"]]}, {"type": "table", "heading": "Sherry Dressing", "rows": [["Sherry vinegar", "200 ml"], ["Shallots", "50 g"], ["Dijon mustard", "30 g"], ["Liquid honey", "20 g"], ["Olive oil", "300 ml"], ["Rapeseed oil (or sunflower)", "400 ml"], ["Salt & pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Sherry dressing: whisk sherry vinegar with minced shallots, Dijon mustard, and honey.", "Slowly whisk in the olive oil and rapeseed oil to emulsify; season with salt and pepper.", "Grill the cooked octopus over high heat until lightly charred at the edges.", "Toss the braised peppers, fennel shavings, roasted garlic, and olives with a little of the sherry dressing.", "Slice the octopus, plate over the dressed vegetables.", "Finish with lemon zest, more sherry dressing, and a scatter of parsley and mint julienne."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Mini Lettuce, Caesar Dressing, Parmesan, Bacon Croutons', NULL, 'Salads & Starters', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Plate", "rows": [["Mini lattich leaves (~8 pcs)", "150 g"], ["Parmesan, shaved", "30 g"], ["Caesar dressing", "100 g"], ["Bacon (speck)", "30 g"], ["Croutons", "15 g"]]}, {"type": "table", "heading": "Caesar Dressing", "rows": [["Egg yolk", "200 g"], ["White wine vinegar", "250 g"], ["Mustard", "100 g"], ["Lemon juice", "50 ml"], ["Worcestershire sauce", "10 ml"], ["Black pepper", "5 g"], ["Vegetable stock", "1.5 L"], ["Rapeseed oil", "1.75 L"], ["Anchovies, washed", "100 g"], ["Garlic, no germ", "30 g"], ["Olive oil", "500 ml"], ["Parmesan", "500 g"], ["Salt", "15–25 g"], ["Tabasco", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Caesar dressing: blend egg yolk, white wine vinegar, mustard, lemon juice, Worcestershire sauce, black pepper, anchovies, and garlic until smooth.", "With the blender running, slowly stream in the olive oil and rapeseed oil to emulsify into a thick dressing.", "Thin to the desired consistency with vegetable stock, then whisk in the grated parmesan. Season with salt and Tabasco to taste.", "Render the bacon (speck) until crisp; toss the croutons in a little of the rendered fat.", "Toss the mini lattich leaves with the Caesar dressing.", "Plate, top with shaved parmesan, crispy bacon, and croutons."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Mixed Tomato Salad with Basil Pesto & Burrata', NULL, 'Salads & Starters', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Plate", "rows": [["Cherry tomatoes, mixed", "200 g"], ["Stracciatella di burrata", "80 g"], ["Basil pesto", "20 g"], ["Pine nuts", "5 g"], ["Extra virgin olive oil", "9 g"], ["White balsamic", "5 g"], ["Fleur de sel / pepper", "to taste"]]}, {"type": "table", "heading": "Basil Pesto", "rows": [["Garlic cloves", "3"], ["Pine nuts", "100 g"], ["Fresh basil leaves", "150 g"], ["Mild olive oil", "200 ml"], ["Parmesan", "50 g"], ["Salt, pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Basil pesto: blend garlic, pine nuts, basil leaves, and mild olive oil until mostly smooth.", "Fold in the grated parmesan by hand (rather than blending it in) to keep the pesto from turning bitter; season with salt and pepper.", "Halve or quarter the cherry tomatoes, season lightly with fleur de sel and pepper.", "Dress the tomatoes with olive oil and white balsamic.", "Plate the dressed tomatoes, tear the stracciatella di burrata over the top.", "Finish with dots of basil pesto, toasted pine nuts, and a final drizzle of olive oil."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Yuzu Dressing', NULL, 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Olive oil", "50 ml"], ["Orange ponzu", "80 ml"], ["Usukuchi light soy sauce", "80 ml"], ["Mirin", "40 ml"], ["Citrus juice", "40 ml"], ["Sancho pepper", "to taste"], ["Yuzu kosho (green)", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Combine olive oil, orange ponzu, usukuchi soy sauce, mirin, and citrus juice in a bowl or jar.", "Whisk (or shake, if in a jar) until combined — this dressing separates, so mix again just before serving.", "Season with a small amount of sancho pepper and green yuzu kosho, tasting as you go since both are potent.", "Store refrigerated; whisk or shake before each use."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Beetroot Pesto', 'Rebové besto', 'Dressings & Cold Sauces', 'Easy', NULL, NULL, '45 min', NULL, NULL, '[{"type": "table", "rows": [["Beetroot", "100 g (roast 150°C, 45 min)"], ["Coriander", "10 g"], ["Rice vinegar", "to taste"], ["Parmesan, grated", "20 g"], ["Pine nuts", "20 g"], ["Salt", "to taste"], ["Garlic paste", "1/4 clove"]]}, {"type": "steps", "heading": "Method", "items": ["Roast the beetroot whole, wrapped in foil, at 150°C for about 45 minutes until a knife slides in easily. Cool and peel.", "Roughly chop the roasted beetroot and blend with coriander, a splash of rice vinegar, and the garlic paste.", "Pulse in the pine nuts and grated parmesan, keeping some texture rather than blending completely smooth.", "Season with salt to taste. Loosen with a little olive oil or water if too thick."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Salad Dressing Mix', NULL, 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["1 — Lime", "100 g"], ["2 — Sugar", "100 g"], ["3 — Salt", "pinch"], ["4 — Pepper", "pinch"], ["5 — Water", "20 g"], ["6 — Sudachi", "15 g"], ["7 — Oil (add last)", "50 g"]]}, {"type": "text", "heading": "Method", "text": "Combine ingredients 1–6, then whisk in the oil last to emulsify."}, {"type": "text", "text": "A second draft of this dressing: 100 g lime, 35 g olive oil, ~30 g mirin, 20 g water, 3 pinches pepper, 15 g sudachi."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Hummus', NULL, 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Chickpeas, cooked", "1 kg"], ["Tahini", "250 g"], ["Salt", "~24 g (+20 g)"], ["Garlic", "100 g"], ["Stock", "600 g (+200–250 g)"], ["Sushi vinegar", "110 g"], ["Lime", "40 g"]]}, {"type": "steps", "heading": "Method", "items": ["Drain the cooked chickpeas well, reserving a little of the cooking liquid or stock.", "Blend chickpeas, tahini, garlic, and half the stock until it starts to come together.", "With the blender running, add the sushi vinegar and lime juice, then stream in the remaining stock until silky smooth.", "Season with salt, adjusting to taste — blend again briefly to fully incorporate air for a lighter texture.", "For the beetroot variation: blend in 500 g roasted, peeled beetroot with the base recipe, adjusting stock/liquid by about 300 g to keep the consistency the same."]}, {"type": "text", "heading": "Beetroot variation", "text": "Add 500 g cooked beetroot + 300 g proportionally to the base recipe."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Black Garlic Aioli', NULL, 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Black garlic cloves", "100 g"], ["Egg yolk", "60 g"], ["Dijon mustard", "20 g"], ["Apple vinegar", "20 g"], ["Rapeseed oil", "700 g"], ["Water", "20–30 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Blend the black garlic cloves with egg yolk, Dijon mustard, and apple vinegar until smooth.", "With the blender or whisk running continuously, drizzle in the rapeseed oil very slowly at first to form a stable emulsion, speeding up once it thickens.", "Thin to the desired consistency with the water, added a little at a time.", "Taste and adjust seasoning; store refrigerated in a sealed container."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Guacamole (House Style)', 'Rice-vinegar finished guacamole', 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, 9.65, 9.65, '[{"type": "table", "rows": [["Avocado (net, pitted & peeled)", "~900 g (from 4.5 kg whole)"], ["Vegetable mayonnaise", "80 g"], ["Salt", "7 g"], ["Black pepper", "3 g"], ["Sushi vinegar", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Halve, pit, and scoop the avocado flesh.", "Mash to the desired texture (chunky or smooth).", "Fold in vegetable mayonnaise, salt, pepper, and sushi vinegar (used here in place of lime for acidity).", "Taste and adjust seasoning. Press plastic wrap directly onto the surface to store and limit browning."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Cherry Tomato Salsa', NULL, 'Dressings & Cold Sauces', 'Easy', NULL, '8 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Cherry tomatoes", "300 g"], ["Cashews", "30 g"], ["Salt", "3 g"], ["Black pepper", "1 g"], ["Manchego cheese", "60 g"], ["Balsamic / sweet soy reduction", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Halve the cherry tomatoes, season with salt, and dry (dehydrator or low oven) for about 8 hours.", "Once dried, combine with cashews, pepper, grated manchego, and the balsamic/sweet soy reduction in a mortar.", "Pound/mix together to a rough salsa texture."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Avocado Salsa', 'Fresh, chunky salsa — reconstructed to fill the empty source sheet', 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Avocado, diced", "200 g"], ["Red onion, fine dice", "30 g"], ["Cherry tomato, diced, seeds removed", "80 g"], ["Red chilli, deseeded and finely chopped", "5 g"], ["Coriander, chopped", "5 g"], ["Lime juice", "15 g"], ["Olive oil", "10 g"], ["Salt", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Dice the avocado just before serving to prevent browning.", "Combine onion, tomato, chilli, and coriander in a bowl.", "Fold in the diced avocado gently — keep the pieces intact rather than mashing.", "Dress with lime juice and olive oil, season with salt, and toss lightly to coat.", "Taste and adjust acidity/heat; serve immediately for best colour and texture."]}, {"type": "text", "text": "Note: the original source sheet for this recipe had only the title recorded — this version was built to match the style of the kitchen''s other fresh salsas. Adjust to match what''s actually served."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Beetroot Salsa', 'Roasted beetroot salsa — pairs well with the beetroot gyoza', 'Dressings & Cold Sauces', 'Easy', NULL, NULL, '1 hr', NULL, NULL, '[{"type": "table", "rows": [["Beetroot, roasted and diced", "200 g"], ["Shallot, fine dice", "25 g"], ["Red chilli, deseeded and finely chopped", "5 g"], ["Coriander, chopped", "5 g"], ["Orange or yuzu juice", "15 g"], ["Rice vinegar", "10 g"], ["Olive oil", "15 g"], ["Toasted sesame seeds", "5 g"], ["Salt", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Roast whole beetroot, wrapped in foil, at 180°C until a knife slides in easily (about 45–60 minutes). Cool, peel, and dice into small cubes.", "Combine beetroot, shallot, chilli, and coriander in a bowl.", "Whisk orange/yuzu juice, rice vinegar, and olive oil together, then pour over the beetroot mixture and toss to coat.", "Season with salt, scatter over toasted sesame seeds, and toss once more.", "Rest 10 minutes before serving to let the flavours combine."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Classic Guacamole', 'Traditional version, alongside the house-style recipe', 'Dressings & Cold Sauces', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Avocado, ripe", "300 g"], ["Red onion, fine dice", "30 g"], ["Tomato, deseeded and diced", "60 g"], ["Jalapeño or green chilli, finely chopped", "5 g"], ["Coriander, chopped", "5 g"], ["Garlic, finely grated", "2 g"], ["Lime juice", "20 g"], ["Salt", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Halve, pit, and scoop the avocado into a bowl.", "Mash roughly with a fork, leaving some texture — guacamole shouldn''t be a smooth purée.", "Fold in onion, tomato, chilli, coriander, and garlic.", "Dress with lime juice, season with salt, and mix gently to combine.", "Taste and adjust lime/salt/heat. Press plastic wrap directly onto the surface to store and limit browning."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Nuoc Cham (Vietnamese Dipping Sauce)', 'Yields ~400 ml', 'Dressings & Cold Sauces', 'Easy', 'Yields ~400 ml', NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Fish sauce", "60 ml"], ["Sugar", "60 g"], ["Lime juice", "60 ml"], ["Water", "120 ml"], ["Garlic, finely minced", "10 g"], ["Red chilli, finely chopped", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Dissolve sugar in warm water.", "Stir in fish sauce and lime juice.", "Add minced garlic and chilli.", "Taste and balance — should hit sweet, sour, salty, and spicy all at once. Adjust lime/sugar/fish sauce to taste.", "Best made fresh the day of service; garlic and chilli settle and mellow if stored too long."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sushi Rice (Shari)', 'Foundation recipe — makes ~1.6 kg', 'Sushi Basics', 'Easy', NULL, '30 min', '10 min', NULL, NULL, '[{"type": "table", "heading": "Rice", "rows": [["Short-grain sushi rice", "1 kg"], ["Water (for cooking)", "1.1 L"], ["Kombu (optional)", "1 small piece"]]}, {"type": "table", "heading": "Sushi Vinegar (Awase-zu)", "rows": [["Rice vinegar", "180 g"], ["Sugar", "90 g"], ["Salt", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Rinse rice in cold water until it runs mostly clear; drain and let sit 20–30 minutes.", "Cook rice with water (and kombu, removed before boiling) — rice cooker or stovetop, then rest covered 10 minutes off heat.", "Meanwhile warm vinegar, sugar, and salt just until dissolved (don''t boil); cool to room temperature.", "Turn hot rice into a wide wooden or non-reactive tub (hangiri). Pour vinegar mixture over in stages, folding with a rice paddle using cutting motions — never stir or mash.", "Fan the rice as you fold to cool it quickly and give it a glossy sheen.", "Cover with a damp cloth and use within a few hours at room temperature — never refrigerate sushi rice."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Nigiri — Shaping Technique', 'Per piece', 'Sushi Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Piece", "rows": [["Sushi rice (shari)", "17 g"], ["Sashimi-grade fish, sliced", "12 g"], ["Wasabi", "0.5 g"], ["Tezu (hand-vinegar: water + rice vinegar, 10:1)", "5 ml, for hands"]]}, {"type": "steps", "heading": "Method", "items": ["Wet fingers with tezu to prevent sticking.", "Scoop 17 g of rice and gently roll into an oval log — do not compact hard, keep it airy.", "Lay the fish slice across your fingers, dab 0.5 g wasabi in the centre.", "Place the rice oval onto the fish, then flip the whole piece over into your palm.", "Press gently with index and middle finger along the length, then press the sides in with thumb and forefinger to square the ends.", "One final light press on top to set the shape — the rice should just hold together, not be compacted."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Hosomaki — Thin Roll Technique', 'Per roll (yields 6–8 pieces)', 'Sushi Basics', 'Easy', '8 portions', NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Roll", "rows": [["Nori, half sheet", "1"], ["Sushi rice", "80 g"], ["Filling (e.g. tuna, cucumber, avocado)", "25 g"]]}, {"type": "steps", "heading": "Method", "items": ["Lay nori rough-side up on the mat, shiny side down.", "Spread the 80 g of rice evenly over the nori, leaving a 1.5cm strip bare at the top edge.", "Lay the 25 g of filling in a line across the centre of the rice.", "Lift the mat edge closest to you and roll forward over the filling, using the mat to shape and tighten as you go.", "Roll all the way to seal on the bare nori edge, moistened lightly to stick.", "Slice into 6–8 pieces with a sharp, wet knife, wiping the blade between cuts."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Uramaki — Inside-Out Roll Technique', 'Per roll (yields 8 pieces)', 'Sushi Basics', 'Easy', '8 portions', NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Roll", "rows": [["Nori, full sheet", "1"], ["Sushi rice", "150 g"], ["Sesame seeds or tobiko, for coating", "10 g"], ["Filling (fish, vegetables, etc.)", "60 g"]]}, {"type": "steps", "heading": "Method", "items": ["Place nori on the mat, spread the 150 g of rice evenly to the edges, and sprinkle the 10 g of sesame seeds/tobiko over the rice.", "Flip the whole sheet over so the rice faces down onto the (cling-film-wrapped) mat.", "Lay the 60 g of filling in a line across the centre of the nori.", "Roll forward using the mat, applying even pressure to shape into a firm cylinder, sealing the far edge.", "Slice into 8 pieces with a sharp, wet knife."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tamagoyaki (Sweet Rolled Omelette)', NULL, 'Sushi Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Eggs", "4"], ["Dashi (or water)", "40 ml"], ["Sugar", "15 g"], ["Soy sauce", "5 ml"], ["Mirin", "10 ml"], ["Salt", "pinch"], ["Oil, for the pan", "as needed"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk eggs with dashi, sugar, soy sauce, mirin, and salt until smooth — avoid over-whipping to keep it silky, not foamy.", "Heat a rectangular tamagoyaki pan (or small non-stick pan) over medium-low heat, wipe with oiled paper.", "Pour a thin layer of egg mixture to coat the base; as it sets, roll it up from one end to the other.", "Push the roll back, oil the pan again, pour in the next thin layer, lifting the cooked roll so the new egg flows underneath.", "Repeat, rolling each new layer around the growing log, until all the mixture is used.", "Shape the warm roll in a bamboo mat or clean cloth to square off the edges, rest, then slice."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Gari (Pickled Sushi Ginger)', NULL, 'Sushi Basics', 'Easy', NULL, '30 min', '24 hr', NULL, NULL, '[{"type": "table", "rows": [["Young ginger, peeled", "300 g"], ["Salt", "10 g"], ["Rice vinegar", "250 ml"], ["Sugar", "120 g"], ["Water", "60 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Slice ginger paper-thin, preferably with a mandoline, along the grain.", "Toss with salt, let sit 20–30 minutes, then squeeze out excess moisture.", "Bring vinegar, sugar, and water to a simmer until sugar dissolves.", "Pack the ginger into a clean jar, pour the hot pickling liquid over to cover completely.", "Cool, then refrigerate at least 24 hours before using — it will turn a natural pale pink over time."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Fresh Wasabi Paste', 'Per 10 portions', 'Sushi Basics', 'Easy', '10 portions', NULL, '3 min', NULL, NULL, '[{"type": "table", "rows": [["Fresh wasabi rhizome", "40 g (yields ~10 portions, 4 g each)"]]}, {"type": "steps", "heading": "Method", "items": ["Trim any knobbly bits and peel lightly.", "Grate in small circular motions on a sharkskin grater (oroshigane) or the finest microplane — this releases the aromatic oils best.", "Mound the paste and let it rest 2–3 minutes at room temperature to let the pungency fully develop before serving.", "Portion at roughly 4 g per cover. Use within an hour — fresh wasabi loses its aroma quickly once grated."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sushi Vinegar — Master Ratio (Awase-zu)', 'Standard house ratio for seasoning sushi rice', 'Sushi Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Rice vinegar", "6 parts"], ["Sugar", "3 parts"], ["Salt", "1 part"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all in a pot and warm gently, stirring, just until the sugar and salt dissolve — do not boil.", "Cool fully before using on rice. Keeps refrigerated for several weeks.", "Use roughly 80–100ml of this mixture per 1kg of cooked sushi rice, adjusting to taste."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chirashi Bowl — Assembly', 'Per portion', 'Sushi Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Portion", "rows": [["Sushi rice, seasoned and cooled", "200 g"], ["Assorted sashimi-grade fish, sliced", "100 g"], ["Tamagoyaki, sliced into strips", "30 g"], ["Cucumber, ribbons or julienne", "20 g"], ["Avocado, sliced", "30 g"], ["Ikura or tobiko", "15 g"], ["Nori, cut into fine strips (kizami nori)", "1 g"], ["Pickled ginger (gari)", "10 g"], ["Soy sauce", "to serve"], ["Wasabi", "2 g"]]}, {"type": "steps", "heading": "Method", "items": ["Fill the base of a wide bowl with the sushi rice.", "Arrange the fish, tamagoyaki, cucumber, and avocado decoratively over the rice, working in small clusters by colour.", "Top with ikura/tobiko and a scatter of kizami nori.", "Serve with pickled ginger, soy sauce, and wasabi on the side."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Temaki (Hand Roll) — Technique', 'Per hand roll', 'Sushi Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Hand Roll", "rows": [["Nori, half sheet", "1"], ["Sushi rice", "60 g"], ["Filling (fish, vegetables, herbs)", "35 g"], ["Wasabi", "1 g"]]}, {"type": "steps", "heading": "Method", "items": ["Hold the nori half-sheet in your palm, shiny side down.", "Spread the 60 g of rice diagonally across the left third of the sheet.", "Dab the wasabi onto the rice, then lay the 35 g of filling diagonally across it.", "Fold the bottom left corner of the nori up and over the filling, then continue rolling into a cone shape.", "Dab a grain of rice on the final corner to seal. Serve and eat immediately, while the nori is still crisp."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sushi Station Basics', 'Ponzu / Unagi / Rice / Vinegar', 'Sushi Station & Cold Dishes', 'Medium', NULL, NULL, '4 hr', NULL, NULL, '[{"type": "table", "heading": "Ponzu", "rows": [["Soy sauce", "500 ml"], ["Mirin", "500 ml"], ["Rice vinegar", "167 ml"], ["Sake", "167 ml"], ["Sugar", "167 g"], ["Kombu", "3 pieces (~7 g each)"]]}, {"type": "table", "heading": "Unagi Sauce (yield ≈ 690 g)", "rows": [["Soy sauce", "300"], ["Water", "33"], ["Mirin", "333"], ["Sugar", "333"], ["Star anise", "to taste"], ["Leek", "66"], ["Eel bones", "133"]]}, {"type": "table", "heading": "Sweet Soy Glaze (mango-orange)", "rows": [["Soy sauce", "500 (from 750)"], ["Mirin", "500 (from 750)"], ["Sugar", "300"], ["Orange", "100"], ["Mango purée", "100"]]}, {"type": "table", "heading": "Charred Onion Mix", "rows": [["Red onion", "700 g"], ["White onion", "700 g"], ["Shallot", "150 g"], ["Chilli (feferón)", "5 pcs"], ["Ginger", "80 g"], ["Garlic", "40 g"]]}, {"type": "list", "heading": "Sushi Rice", "items": ["Rice: 870 g net → 930 g cooked", "Water: 6 cups → 2450 g total with water", "Cook: start timer at 01:35", "Portion: 170 g rice per sushi order"]}, {"type": "table", "heading": "Sushi Vinegar (Soshi Ocot)", "rows": [["Sugar", "1800 g"], ["Salt", "500 g"], ["Kombu", "5 pieces (~7 g each)"], ["Shiragiku vinegar", "1200 g"], ["Rice vinegar", "1200 g"]]}, {"type": "table", "heading": "Amazu (sweet vinegar)", "rows": [["Water", "600 ml"], ["Vinegar", "600 ml"], ["Sugar", "333 g"]]}, {"type": "steps", "heading": "Method Notes", "items": ["Ponzu: combine all ingredients, let the kombu infuse cold for at least 4 hours (or overnight), then strain.", "Unagi sauce: simmer soy sauce, water, mirin, sugar, star anise, and leek with the eel bones for 30–40 minutes to extract flavour and body, then strain and cool — it should coat a spoon.", "Sweet soy glaze: warm soy sauce and mirin with sugar until dissolved, then blend in the orange and mango purée; simmer briefly to marry the flavours.", "Charred onion mix: char the onions, shallot, and chilli over very high heat or open flame until blackened in spots, then finely chop with the ginger and garlic — used as a flavour base for stocks and glazes.", "Sushi rice: cook rice with the specified water ratio, then fold through the sushi vinegar while still hot (see Sushi Vinegar recipe); portion at 170 g per order.", "Sushi vinegar (Soshi Ocot): warm all ingredients together just until the sugar and salt dissolve; cool before folding into hot rice.", "Amazu: combine water, vinegar, and sugar, warm gently until the sugar dissolves; use for quick-pickling garnishes."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Ponzu & Teriyaki', 'Large batch', 'Sushi Station & Cold Dishes', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Ponzu", "rows": [["Mirin", "3 L"], ["Soy sauce", "3 L"], ["Rice vinegar", "1 L"], ["Sake (reduced to cook off alcohol)", "1 L"], ["Sugar", "1 L (by volume)"]]}, {"type": "table", "heading": "Teriyaki", "rows": [["Mirin", "2 L"], ["Sake", "2 L"], ["Soy sauce", "1 L"], ["Sugar", "1.3 (as written)"]]}, {"type": "text", "text": "Matches the smaller Ponzu batch — this is the scaled-up version."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Rice Cracker', 'Rice Krek', 'Sushi Station & Cold Dishes', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Baking soda", "1.25"], ["Water", "0.5"], ["Egg white", "250 g"], ["Salt", "25 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk the baking soda into the water until dissolved.", "Whip the egg whites with the salt to soft peaks.", "Gently fold the baking soda water through the whipped egg whites.", "Spread very thinly onto a lined tray or silicone mat.", "Dry at low temperature (around 90–100°C) until fully crisp, or dehydrate for several hours.", "Once dry, break into shards, or fry briefly in hot oil until puffed and crisp if a lighter, puffed cracker is wanted."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sushi Vinegar (alternate batch)', NULL, 'Sushi Station & Cold Dishes', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Sugar (carb)", "1800"], ["Salt (NaCl)", "500"], ["Kombu", "5 pieces"], ["Acid (vinegar)", "1200"], ["Fruit (juice, orange/mango)", "1200"]]}, {"type": "text", "text": "Matches \"Soshi Ocot\" elsewhere in this book — same ratios, different labelling."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Rice Vinegar Blend', 'For beef/tempura service', 'Sushi Station & Cold Dishes', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "text", "text": "Plating note: beef; shrimp tempura with avocado, served over rice; for 2 portions."}, {"type": "table", "rows": [["Sugar", "4.5 kg"], ["Salt", "1.25 kg"], ["Kombu", "1 kg"], ["Yusen vinegar", "3.5 L"], ["Shiragiku vinegar", "1.5 L"]]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Amazu Marinade (Amazu-zu)', 'Sweet vinegar dilution — 1 portion ≈ 1.5 kg', 'Sushi Station & Cold Dishes', 'Easy', '1 portions', NULL, NULL, 1.38, 0.9, '[{"type": "table", "rows": [["Suehiro (seasoned rice vinegar)", "600 g"], ["Water", "600 g"], ["Sugar", "333 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all three in a container and whisk until the sugar fully dissolves (warm gently if needed to speed this up).", "Chill. Use as a light pickling/dressing liquid for onion, cucumber, or daikon garnishes."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Nikiri Shoyu', 'Classic soy glaze for sashimi/nigiri — yields ~250 ml', 'Sushi Station & Cold Dishes', 'Easy', 'Yields ~250 ml', '5 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Soy sauce", "200 ml"], ["Mirin", "40 ml"], ["Sake", "20 ml"], ["Kombu", "5 g"], ["Katsuobushi", "5 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine mirin and sake in a pot, bring to a boil for 1 minute to cook off the alcohol.", "Add soy sauce and kombu, bring back to a gentle simmer, then remove from heat just before it boils.", "Scatter in the katsuobushi, let steep 5 minutes.", "Strain through a fine sieve without pressing the flakes. Cool completely before use.", "Brush lightly onto nigiri or sashimi instead of dipping in plain soy — gives a glossier, more rounded flavour."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Kobe Kagoshima', NULL, 'Sushi Station & Cold Dishes', 'Easy', NULL, '30 min', NULL, NULL, NULL, '[{"type": "table", "heading": "Black Truffle Sauce", "rows": [["Chicken reduction", "100 g"], ["Black truffle, grated", "35 g"], ["Cuttlefish ink", "1/2"], ["Truffle oil", "8 g"], ["Grapeseed oil", "30 g"], ["Rice vinegar", "10–15 ml"]]}, {"type": "text", "text": "Method: Combine all ingredients except the oils in a Thermomix. With the mixer running, slowly stream in the oils as you would when making mayonnaise. Season and store."}, {"type": "text", "heading": "Steamed Jerusalem Artichokes", "text": "Wash and rinse. Steam for 10–15 minutes before serving, depending on size and firmness."}, {"type": "list", "heading": "Salad with Chestnut Chips & Turmeric-Pickled Onion", "items": ["Thai basil", "Micro coriander", "Chervil", "Nasturtium", "Rocket (arugula)", "Red chard", "Truffle ponzu — lemon ponzu : truffle oil, 5:1", "Spring onion, pickled in turmeric vinegar"]}, {"type": "steps", "heading": "Salad Assembly", "items": ["Fry thin gastanet/chestnut chips until crisp and golden; drain and season lightly with salt.", "Pickle the sliced spring onion in turmeric vinegar for at least 30 minutes before serving.", "Toss the Thai basil, micro coriander, chervil, nasturtium, rocket, and red chard together just before plating.", "Dress lightly with the truffle ponzu (lemon ponzu : truffle oil, 5:1).", "Plate the dressed salad alongside the steamed Jerusalem artichokes and black truffle sauce, topped with chestnut chips and pickled onion."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', '"SPA" Soup/Dressing Base', NULL, 'Soups', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Avocado", "1 pc → 130 g"], ["Cucumber", "2 pcs → 130 g (+25 g)"], ["Celery stalk", "65 g"], ["Sour cream", "155 g"], ["Coconut milk", "100 g"], ["Garlic oil", "50 g"], ["Spice mix", "1 g"], ["Salt", "15 g"], ["Dill stalks", "30 g"], ["Sushi vinegar", "30 g"], ["Stock", "200 g"]]}, {"type": "text", "text": "Note: cucumber quantity in the original notes was a bit ambiguous (listed as \"2 pcs → 130g (+25g)\") — confirm against the original before scaling up."}, {"type": "steps", "heading": "Method", "items": ["Peel and roughly chop the avocado and cucumber.", "Blend avocado, cucumber, celery, coconut milk, garlic oil, spice mix, salt, and dill together with the stock until completely smooth.", "Pass through a fine sieve for a silkier texture if serving chilled as a soup.", "Stir in the sushi vinegar last, tasting and adjusting acidity.", "Chill thoroughly before serving; whisk again before plating as the ingredients can separate."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Dried Mushroom Consommé', NULL, 'Soups', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Dried ceps", "300 g"], ["Dried Portobello", "150 g"], ["Water", "15 L"], ["Dry shitake", "5 pcs"], ["Bay leaf", "3 pcs"], ["Fresh green peppercorns", "5 pcs"], ["Kombu (to finish)", "1 piece"]]}, {"type": "text", "heading": "Method", "text": "Boil for about 2 hours, strain, and reserve."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pho Bo Bowl (Assembly)', 'Per portion', 'Soups', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Portion", "rows": [["Beef stock (pho broth), hot", "500 ml"], ["Rice noodles, dry weight", "80 g"], ["Beef, thinly sliced (rare, to cook in hot broth)", "80 g"], ["Beansprouts", "40 g"], ["Red chilli, sliced", "2 g"], ["Coriander leaves", "3 g"], ["Spring onion, sliced", "5 g"], ["Beef gyoza", "3 pcs"], ["Chilli oil", "5 g"], ["Lime oil", "3 g"], ["Amazu-pickled onion", "15 g"], ["Lime wedge", "1"]]}, {"type": "steps", "heading": "Assembly", "items": ["Blanch rice noodles and place in the serving bowl.", "Lay the raw sliced beef over the noodles.", "Ladle hot beef stock over the noodles and beef — the residual heat gently cooks the beef as it''s poured.", "Top with beansprouts, beef gyoza, spring onion, and chilli.", "Finish with chilli oil, lime oil, pickled onion, and coriander. Serve with a lime wedge on the side."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Dashi (Kombu-Katsuo Stock)', 'Foundation stock — makes ~1 L', 'Soups', 'Easy', 'Makes 1 L', '2 min', '30 min', NULL, NULL, '[{"type": "table", "rows": [["Water", "1.1 L"], ["Kombu", "10 g"], ["Katsuobushi (bonito flakes)", "20 g"]]}, {"type": "steps", "heading": "Method", "items": ["Soak kombu in cold water for at least 30 minutes (or overnight in the fridge).", "Slowly heat the water with the kombu to just below a simmer, then remove the kombu right before it boils (boiling makes it bitter/slimy).", "Bring the water to a light boil, then remove from heat and scatter in the katsuobushi.", "Let steep undisturbed for 2 minutes, then strain through a fine sieve without pressing the flakes (this keeps the dashi clear)."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Miso Soup Base', NULL, 'Soups', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Dashi", "1 L"], ["Miso paste (white or awase)", "60–80 g"], ["Silken tofu, diced", "150 g"], ["Wakame, rehydrated", "10 g"], ["Spring onion, sliced", "to garnish"]]}, {"type": "steps", "heading": "Method", "items": ["Bring the dashi to a gentle simmer.", "Ladle a little hot dashi into a bowl with the miso paste and whisk until smooth, then stir this back into the pot — never boil miso directly, it dulls the flavour and aroma.", "Add tofu and wakame, warm through gently without boiling.", "Ladle into bowls and garnish with spring onion."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Ramen Tare (Shoyu Base)', 'Concentrated seasoning base for ramen broth', 'Soups', 'Easy', NULL, '20 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Soy sauce", "300 ml"], ["Mirin", "60 ml"], ["Sake", "60 ml"], ["Kombu", "5 g"], ["Katsuobushi", "10 g"], ["Dried shiitake", "2 pcs"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all ingredients in a pot and bring gently to a simmer.", "Simmer 10 minutes, then remove from heat and let steep 20 minutes.", "Strain. Store the tare separately from the broth.", "To serve: spoon 30–40ml of tare into each bowl, then top with hot broth and noodles — this keeps seasoning consistent bowl to bowl."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Congee Base', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '1.5 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Jasmine rice", "150 g"], ["Water or stock", "1.5 L"], ["Ginger, sliced", "15 g"], ["Salt", "5 g"], ["White pepper", "1 g"]]}, {"type": "steps", "heading": "Method", "items": ["Rinse the rice, then optionally toss with a little oil and salt and let sit 15 minutes (this helps break the grains down faster).", "Combine rice, water/stock, and ginger in a heavy pot. Bring to a boil, then reduce to a low simmer.", "Simmer uncovered, stirring occasionally to prevent sticking, for 1–1.5 hours until the rice has broken down into a thick, creamy porridge.", "Season with salt and white pepper. Thin with more hot water/stock if needed.", "Serve with toppings of choice — century egg, shredded chicken, fried shallots, spring onion, youtiao."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tonkotsu Ramen Broth', 'Pork bone broth — yields ~3 L, serves 6–8 · long cook', 'Soups', 'Medium', 'Serves 6–8', '10 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Pork trotters, split", "1.5 kg"], ["Pork neck bones", "1.5 kg"], ["Water", "4 L"], ["Onion, halved", "1"], ["Garlic, whole head, halved", "1"], ["Ginger, sliced", "40 g"], ["Spring onion, whites only", "4 stalks"]]}, {"type": "steps", "heading": "Method", "items": ["Blanch trotters and neck bones in boiling water for 10 minutes to remove impurities, then rinse well under cold water, scrubbing off any scum.", "Return the cleaned bones to a large pot with 4 L fresh water. Bring to a rolling boil, then keep at a hard, rolling boil (not a gentle simmer — this is what emulsifies the fat and gives tonkotsu its signature cloudy white colour) for 8–10 hours, topping up water as needed to keep bones submerged.", "Add onion, garlic, ginger, and spring onion whites for the final 2 hours of cooking.", "Strain through a fine sieve, pressing gently to extract all the emulsified fat and collagen.", "Season the broth with tare (soy or shio) just before serving — the base broth itself stays unseasoned so it can be used for multiple styles.", "Serve over ramen noodles with chashu pork, soft-boiled egg, spring onion, and nori."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tom Yum Goong (Prawn & Lemongrass Soup)', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '10 min', '5 min', NULL, NULL, '[{"type": "table", "rows": [["Chicken or prawn stock", "1 L"], ["Tom Yum paste", "80 g"], ["King prawns, shell-on", "400 g"], ["Mushrooms (straw or oyster), halved", "150 g"], ["Lemongrass, bruised and cut into batons", "2 stalks"], ["Kaffir lime leaves, torn", "4"], ["Galangal, sliced", "20 g"], ["Fish sauce", "30 ml"], ["Lime juice", "40 ml"], ["Bird''s eye chilli, bruised", "3"], ["Coriander leaves", "to garnish"], ["Evaporated milk (for tom yum nam khon, optional)", "100 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Peel the prawns, reserving the shells and heads. Quickly fry the shells/heads in a splash of oil until fragrant and red, then add to the stock and simmer 10 minutes for extra depth; strain out and discard.", "Bring the strained stock to a boil, add lemongrass, lime leaves, galangal, and chilli, simmer 5 minutes to infuse.", "Stir in the Tom Yum paste, simmer 2–3 minutes.", "Add mushrooms and prawns, cook until the prawns just turn pink and opaque, 2–3 minutes — do not overcook.", "Season with fish sauce and lime juice off the heat (boiling lime juice makes it bitter). For the creamy version (nam khon), stir in evaporated milk at this point.", "Garnish with coriander and serve immediately."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Laksa (Malaysian Coconut Curry Noodle Soup)', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '10 min', NULL, NULL, NULL, '[{"type": "table", "heading": "Laksa Paste", "rows": [["Dried chillies, soaked", "20 g"], ["Shallot", "80 g"], ["Garlic", "20 g"], ["Galangal", "20 g"], ["Lemongrass, white part only", "2 stalks"], ["Candlenuts or macadamia", "20 g"], ["Belacan (shrimp paste), toasted", "10 g"], ["Turmeric, fresh or 5g ground", "15 g"]]}, {"type": "table", "heading": "Soup", "rows": [["Neutral oil", "30 ml"], ["Chicken stock", "800 ml"], ["Coconut milk", "400 ml"], ["Fish sauce", "20 ml"], ["Palm sugar", "15 g"], ["Rice vermicelli, cooked", "300 g"], ["Prawns, peeled", "200 g"], ["Chicken breast, poached and shredded", "200 g"], ["Beansprouts", "100 g"], ["Fried tofu puffs, halved", "100 g"], ["Hard-boiled egg, halved", "2"], ["Laksa leaf or coriander", "to garnish"]]}, {"type": "steps", "heading": "Method", "items": ["Blend all laksa paste ingredients into a smooth paste, adding a splash of water if needed.", "Fry the paste in oil over medium heat for 8–10 minutes, stirring often, until the oil separates and the raw smell is gone.", "Add chicken stock, bring to a simmer, then stir in coconut milk, fish sauce, and palm sugar. Simmer gently 10 minutes — do not boil hard once coconut milk is added, or it can split.", "Add prawns and simmer until just cooked, 2–3 minutes.", "Divide noodles, shredded chicken, beansprouts, and tofu puffs among bowls. Ladle the hot soup and prawns over.", "Top with hard-boiled egg and laksa leaf/coriander."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Hot and Sour Soup', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '5 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Chicken stock", "1 L"], ["Pork loin, julienned", "120 g"], ["Wood ear mushrooms, rehydrated and sliced", "30 g"], ["Bamboo shoots, julienned", "80 g"], ["Firm tofu, julienned", "150 g"], ["Rice vinegar", "60 ml"], ["White pepper, ground", "5 g"], ["Soy sauce", "30 ml"], ["Sugar", "10 g"], ["Cornstarch slurry (1:1 cornstarch:water)", "40 g"], ["Egg, beaten", "2"], ["Sesame oil", "5 ml"], ["Spring onion, sliced", "to garnish"]]}, {"type": "steps", "heading": "Method", "items": ["Bring the stock to a boil, add pork, mushrooms, and bamboo shoots, simmer 5 minutes until the pork is cooked through.", "Add tofu, then season with vinegar, white pepper, soy sauce, and sugar.", "Stir in the cornstarch slurry gradually while stirring the soup, until lightly thickened.", "Reduce to a gentle simmer, then drizzle in the beaten egg in a thin stream while stirring the soup in one direction, creating fine egg ribbons.", "Finish with sesame oil, taste and adjust the hot-sour balance (more pepper for heat, more vinegar for sour).", "Garnish with spring onion and serve immediately."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Wonton Soup', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '5 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Chicken stock (or dashi-chicken blend)", "1.2 L"], ["Wontons (see Wonton Dough & Filling Technique)", "20 pcs"], ["Soy sauce", "15 ml"], ["Sesame oil", "5 ml"], ["White pepper", "2 g"], ["Baby bok choy, halved", "4"], ["Spring onion, sliced", "to garnish"]]}, {"type": "steps", "heading": "Method", "items": ["Bring the chicken stock to a gentle simmer, season with soy sauce, sesame oil, and white pepper.", "In a separate pot of simmering water, cook the wontons until they float, about 4–5 minutes, then drain briefly.", "Blanch the bok choy in the same water for 1 minute, drain.", "Divide wontons and bok choy among bowls, ladle the hot seasoned stock over.", "Garnish with spring onion and serve immediately."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'French Onion Soup', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '1 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Yellow onions, thinly sliced", "1 kg"], ["Butter", "60 g"], ["Olive oil", "15 ml"], ["Sugar", "10 g"], ["Garlic, minced", "10 g"], ["Plain flour", "15 g"], ["White wine", "100 ml"], ["Beef stock", "1 L"], ["Bay leaf", "1"], ["Thyme", "2 sprigs"], ["Baguette, sliced and toasted", "8 slices"], ["Gruyère, grated", "150 g"]]}, {"type": "steps", "heading": "Method", "items": ["Melt butter with olive oil in a heavy pot. Add onions and sugar, cook over medium-low heat, stirring occasionally, until deeply caramelized and jammy — this takes 45–60 minutes, don''t rush it.", "Add garlic, cook 1 minute, then stir in flour and cook a further minute to remove the raw taste.", "Deglaze with white wine, scraping up any browned bits, and simmer until mostly reduced.", "Add beef stock, bay leaf, and thyme. Simmer 30 minutes, then season to taste.", "Ladle into oven-proof bowls, top with toasted baguette slices and a generous layer of Gruyère.", "Grill/broil until the cheese is melted and golden with bubbling spots. Serve immediately, very hot."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Lobster Bisque', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '45 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Lobster shells and heads (from 2 lobsters)", "500 g"], ["Butter", "60 g"], ["Olive oil", "15 ml"], ["Onion, diced", "100 g"], ["Carrot, diced", "80 g"], ["Celery, diced", "60 g"], ["Garlic, minced", "10 g"], ["Tomato paste", "40 g"], ["Brandy or cognac", "50 ml"], ["White wine", "150 ml"], ["Fish or shellfish stock", "800 ml"], ["Cream", "200 g"], ["Bay leaf", "1"], ["Tarragon", "2 sprigs"], ["Lobster meat, cooked and diced (garnish)", "150 g"]]}, {"type": "steps", "heading": "Method", "items": ["Roast or sauté the lobster shells in butter and oil until deeply red and fragrant, crushing them slightly to release more flavour.", "Add onion, carrot, celery, and garlic, sauté until softened.", "Stir in tomato paste, cook 2 minutes to caramelize slightly.", "Flambé with brandy carefully (stand back, it will ignite), then add white wine and reduce by half.", "Add stock, bay leaf, and tarragon. Simmer 45 minutes to extract maximum flavour from the shells.", "Strain through a fine sieve, pressing firmly on the shells and vegetables to extract all the liquid; discard solids.", "Return to a clean pot, stir in cream, and gently warm through — do not boil hard once cream is added.", "Blend if a completely smooth texture is wanted, then strain again through a fine chinois for silkiness.", "Season to taste, garnish with diced lobster meat, and serve."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Classic Chicken Noodle Soup', 'Serves 6', 'Soups', 'Easy', 'Serves 6', '1.5 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Whole chicken, or chicken thighs/carcass", "1.5 kg"], ["Water", "2.5 L"], ["Onion, quartered", "1"], ["Carrot, chopped", "2"], ["Celery, chopped", "2 stalks"], ["Garlic, whole cloves", "4"], ["Bay leaf", "2"], ["Thyme", "3 sprigs"], ["Egg noodles or dried pasta", "200 g"], ["Parsley, chopped", "to garnish"], ["Salt and pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Place chicken, water, half the onion/carrot/celery, garlic, bay leaf, and thyme in a large pot. Bring to a boil, skim off any scum, then reduce to a gentle simmer.", "Simmer 1–1.5 hours until the chicken is fully cooked and tender.", "Remove the chicken, let cool slightly, then shred the meat, discarding skin and bones. Reserve.", "Strain the stock, discarding the spent vegetables and aromatics. Return the clear stock to the pot.", "Add the remaining fresh onion, carrot, and celery, simmer 15 minutes until tender.", "Add noodles and cook according to packet time until just tender.", "Return the shredded chicken to the pot, warm through, season with salt and pepper.", "Garnish with fresh parsley and serve."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Roasted Butternut Squash Soup', 'Serves 4', 'Soups', 'Easy', 'Serves 4', '35 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Butternut squash, peeled and cubed", "1 kg"], ["Olive oil", "30 ml"], ["Onion, diced", "150 g"], ["Garlic, whole cloves, unpeeled", "4"], ["Butter", "30 g"], ["Vegetable stock", "800 ml"], ["Cream", "100 g"], ["Nutmeg, ground", "1 g"], ["Salt and pepper", "to taste"], ["Toasted pumpkin seeds and sage, to garnish", "optional"]]}, {"type": "steps", "heading": "Method", "items": ["Toss squash cubes and unpeeled garlic cloves with olive oil, salt, and pepper. Roast at 200°C for 30–35 minutes until tender and lightly caramelized at the edges.", "Meanwhile, sweat the onion in butter over low heat until soft and translucent, about 10 minutes.", "Squeeze the roasted garlic out of its skin and add to the onions along with the roasted squash.", "Add vegetable stock, bring to a simmer, and cook 10 minutes to let flavours meld.", "Blend until completely smooth, adding cream and nutmeg. Adjust consistency with more stock if needed.", "Season to taste. Garnish with toasted pumpkin seeds and crispy sage if using."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Minestrone', 'Serves 6', 'Soups', 'Easy', 'Serves 6', '20 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Olive oil", "30 ml"], ["Onion, diced", "120 g"], ["Carrot, diced", "100 g"], ["Celery, diced", "100 g"], ["Garlic, minced", "15 g"], ["Courgette, diced", "150 g"], ["Potato, diced", "150 g"], ["Canned chopped tomatoes", "400 g"], ["Vegetable or chicken stock", "1.2 L"], ["Cannellini beans, cooked", "200 g"], ["Small pasta (ditalini or similar)", "100 g"], ["Parmesan rind (optional, for depth)", "1 piece"], ["Basil, torn", "to garnish"], ["Parmesan, grated", "to serve"]]}, {"type": "steps", "heading": "Method", "items": ["Sweat onion, carrot, and celery in olive oil over medium-low heat until softened, about 10 minutes.", "Add garlic, cook 1 minute, then add courgette and potato, stir to coat.", "Add chopped tomatoes, stock, and the parmesan rind if using. Bring to a simmer and cook 20 minutes until vegetables are tender.", "Add cannellini beans and pasta, simmer until the pasta is just tender, about 10 minutes.", "Remove the parmesan rind. Season to taste.", "Serve topped with torn basil and grated parmesan."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Vichyssoise (Chilled Leek & Potato Soup)', 'Serves 4 — chill at least 4 hrs before serving', 'Soups', 'Easy', 'Serves 4', '20 min', '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Leeks, white part only, sliced", "400 g"], ["Butter", "40 g"], ["Potato, peeled and diced", "300 g"], ["Chicken or vegetable stock", "800 ml"], ["Cream", "150 g"], ["Chives, chopped", "to garnish"], ["Salt and white pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Sweat the leeks gently in butter over low heat until soft but not coloured, about 12–15 minutes.", "Add potato and stock, bring to a simmer, and cook until the potato is fully tender, about 20 minutes.", "Blend until completely smooth, then pass through a fine sieve for a silky texture.", "Stir in the cream, season with salt and white pepper.", "Chill thoroughly, at least 4 hours, ideally overnight — the flavour rounds out as it chills.", "Serve cold, garnished with chopped chives."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Gazpacho (Chilled Spanish Tomato Soup)', 'Serves 4 — chill at least 2 hrs before serving', 'Soups', 'Easy', 'Serves 4', NULL, '2 hr', NULL, NULL, '[{"type": "table", "rows": [["Ripe tomatoes, roughly chopped", "800 g"], ["Cucumber, peeled and chopped", "150 g"], ["Red pepper, chopped", "100 g"], ["Red onion, chopped", "50 g"], ["Garlic", "1 clove"], ["Sherry vinegar", "20 ml"], ["Olive oil, extra virgin", "60 ml"], ["Stale bread, crusts removed (optional, for body)", "40 g"], ["Salt", "to taste"], ["Diced vegetables, to garnish", "optional"]]}, {"type": "steps", "heading": "Method", "items": ["If using bread, soak it briefly in a little water and squeeze out excess.", "Blend tomatoes, cucumber, red pepper, onion, garlic, sherry vinegar, and bread (if using) until completely smooth.", "With the blender running, stream in the olive oil to emulsify.", "Pass through a fine sieve for a silky, refined texture.", "Season with salt, chill thoroughly, at least 2 hours.", "Serve very cold, garnished with a scatter of finely diced tomato, cucumber, and pepper, and a drizzle of olive oil."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'New England Clam Chowder', 'Serves 6', 'Soups', 'Easy', 'Serves 6', '15 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Clams, fresh (or 400g canned clams + juice)", "1 kg"], ["Water (if using fresh clams)", "500 ml"], ["Bacon, diced", "100 g"], ["Butter", "30 g"], ["Onion, diced", "150 g"], ["Celery, diced", "80 g"], ["Plain flour", "40 g"], ["Potato, diced", "300 g"], ["Milk", "400 ml"], ["Cream", "200 g"], ["Bay leaf", "1"], ["Thyme", "2 sprigs"], ["Salt and pepper", "to taste"], ["Parsley, chopped", "to garnish"]]}, {"type": "steps", "heading": "Method", "items": ["If using fresh clams: steam them in a covered pot with water until they open, about 5–8 minutes. Discard any that don''t open. Strain and reserve the cooking liquid, remove clam meat from shells and chop.", "Render the bacon in a heavy pot until crisp, remove and reserve, leaving the fat behind.", "Add butter, onion, and celery to the bacon fat, sweat until softened, about 8 minutes.", "Stir in flour, cook 2 minutes to form a roux.", "Gradually whisk in the reserved clam liquid (or bottled clam juice) to avoid lumps, then add the potato, bay leaf, and thyme.", "Simmer until the potato is tender, about 15 minutes.", "Stir in milk and cream, warm through gently without boiling hard.", "Add the chopped clams and crispy bacon back in, warm through 2–3 minutes.", "Season to taste, garnish with parsley, and serve."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Peking Duck', NULL, 'Meat & Mains', 'Easy', NULL, NULL, '5 hr', NULL, NULL, '[{"type": "steps", "heading": "Method", "items": ["Rinse the duck in cold water, pat dry. Rub the cavity thoroughly with hoisin paste. Sew the cavity closed, then blanch by pouring boiling water over it for 3–5 minutes; hang on a hook.", "Bring water to a boil and pour over the duck again for 3–5 minutes. Hang in a cold place (fridge) for at least 5 hours — ideally 24.", "Once dried, heat the glaze and brush the duck several times, drying with a fan between coats. Once glazed enough, it''s ready to roast (tray underneath to catch drippings).", "Roast at 149°C for 20 minutes, then 180°C for a further 20–25 minutes, watching colour. Rest 15 minutes after roasting."]}, {"type": "table", "heading": "Duck Glaze", "rows": [["Honey", "300 g"], ["Maltose", "300 g"], ["Soy sauce", "100 g"], ["White vinegar", "100 g"], ["Water", "to thin"]]}, {"type": "table", "heading": "Foie Gras Pâté", "rows": [["Chicken liver, cleaned", "350 g"], ["Foie gras", "200 g"], ["Shallot, small dice", "80 g"], ["Garlic, finely chopped", "8 g"], ["Butter", "60 g"], ["Cream", "140 g"], ["Cream", "110 g"]]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Gyoza', 'Components 1, 6', 'Meat & Mains', 'Easy', NULL, '4 min', NULL, NULL, NULL, '[{"type": "table", "heading": "Filling (PK: gyoza plnka)", "rows": [["Duck liver", "140 g"], ["Beef fillet", "220 g"], ["Beef chuck flap", "110 g"], ["Wagyu fat", "80 g"], ["Wagyu trim", "120 g"], ["Reduced teriyaki", "70 ml"], ["Salt", "3 g"], ["White pepper", "2 g"]]}, {"type": "text", "heading": "Per-portion plating", "text": "4 pcs edamame, 3 ml reduced teriyaki, 80 g gyoza filling."}, {"type": "steps", "heading": "Folding & Cooking", "items": ["Place a portion of gyoza filling in the centre of each wrapper.", "Wet the edge of the wrapper with water, fold in half, and pleat from one end to the other to seal tightly.", "Heat a non-stick pan with a little oil, arrange the gyoza flat-side down, and fry until golden on the base.", "Add a splash of water, cover immediately, and steam for 3–4 minutes until the filling is cooked through.", "Remove the lid and let any remaining water evaporate so the base re-crisps before serving.", "Plate with the reduced teriyaki drizzle and edamame as noted per portion."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Veal Spare Ribs (Kalbsspare Ribs)', 'Sous-vide 64°C — 24–48 hrs (check original)', 'Meat & Mains', 'Hard', NULL, '48 hr', '1 hr', NULL, NULL, '[{"type": "table", "heading": "Base", "rows": [["Veal spareribs", "6 kg"]]}, {"type": "table", "heading": "Dry Rub", "rows": [["Fine sea salt", "90 g"], ["Cane sugar", "60 g"], ["Sweet paprika", "22 g"], ["Mustard powder", "15 g"], ["Black pepper", "12 g"]]}, {"type": "table", "heading": "Sous-vide Bag", "rows": [["Butter", "225 g"], ["Fresh thyme", "22 g"], ["Garlic", "45 g"]]}, {"type": "table", "heading": "Glaze", "rows": [["Apple juice (cloudy)", "750 g"], ["Apple vinegar", "150 g"], ["Liquid honey", "120 g"], ["Fresh ginger", "60 g"]]}, {"type": "text", "text": "Note: one copy of this page reads 24 hours sous-vide, another reads 48 hours at 64°C — confirm against the original before running it."}, {"type": "steps", "heading": "Method", "items": ["Combine all dry rub ingredients and coat the veal spareribs evenly on all sides, pressing it in.", "Rest at least 1 hour refrigerated, ideally overnight, to let the rub penetrate.", "Vacuum-seal the ribs with the butter, thyme, and garlic.", "Cook sous-vide at 64°C — confirm 24 vs 48 hours against the original notes before running a full batch, but 24 hours is the safer starting point for veal (more delicate than beef).", "Meanwhile make the glaze: combine apple juice, apple vinegar, honey, and ginger in a pot and simmer until reduced by about half and syrupy.", "Once sous-vide is done, remove the ribs from the bag and pat dry.", "Brush generously with the glaze and finish under a hot grill or salamander, basting with more glaze, until caramelized and lightly charred at the edges."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sous-Vide Cuts Reference', 'Steak/protein menu with cook specs', 'Meat & Mains', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Cuts & sous-vide settings", "rows": [["Côte de Boeuf, Spanish Morucha beef, 300 g", "Sous-vide 54°C, 2 hrs"], ["Veal spare ribs, Holzen calf, 300 g", "see separate recipe"], ["Pork cutlet, Luma pork, 300 g", "Sous-vide 58°C, 1.5 hrs"], ["US Beef flank steak, 250 g", "Sous-vide 54°C, 1.5 hrs"], ["Wagyu burger, Old Cow, 140 g", "Sear à la minute (not sous-vide)"], ["BBQ-marinated thigh steak, Ribelmais-Poularde chicken, 250 g", "Sous-vide 62°C, 1.5 hrs"], ["Tuna, 160 g", "À la minute"], ["Planted steak (plant-based)", "À la minute"]]}, {"type": "text", "text": "General method: season and vacuum-seal each cut with any aromatics noted, cook sous-vide to the listed temperature/time, then finish with a hard, hot sear on a grill or pan just before service for colour and crust. Items marked \"à la minute\" are cooked to order without a sous-vide step."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Truffle Mac and Cheese', NULL, 'Meat & Mains', 'Easy', NULL, '10 min', NULL, NULL, NULL, '[{"type": "table", "heading": "Per portion", "rows": [["Fresh maccheroncini", "120 g"], ["Mac & Cheese sauce", "80 g"]]}, {"type": "table", "heading": "Mac & Cheese Sauce", "rows": [["Butter", "80 g"], ["White flour", "80 g"], ["Whole milk", "1500 ml"], ["Whole cream", "200 ml"], ["Gruyère AOP (aged)", "300 g"], ["Vacherin", "200 g"], ["Parmesan (aged)", "100 g"], ["Truffle paste", "50 g"], ["White truffle oil", "20 g"], ["Salt, nutmeg, cayenne, smoked paprika", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Make a roux by cooking the butter and flour together for 2 minutes over medium heat, stirring constantly.", "Gradually whisk in the whole milk and cream, a little at a time, to avoid lumps, until you have a smooth béchamel.", "Simmer gently for 8–10 minutes, stirring often, until thickened enough to coat the back of a spoon.", "Remove from heat and stir in the Gruyère, Vacherin, and Parmesan until fully melted and smooth.", "Stir in the truffle paste and white truffle oil; season with salt, nutmeg, cayenne, and smoked paprika to taste.", "Cook the fresh maccheroncini in well-salted boiling water until just al dente, drain.", "Toss the pasta through the warm sauce at a ratio of about 120 g pasta to 80 g sauce per portion, and serve immediately."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Confit Wild Mushrooms', 'With garlic and thyme', 'Meat & Mains', 'Easy', NULL, '30 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Wild mushrooms", "1500 g"], ["Rapeseed oil", "1000 g"], ["Garlic cloves", "40 g"], ["Fresh thyme", "15 g"], ["Shallots", "100 g"], ["Peppercorns & allspice", "5 g"], ["White balsamic", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Heat the oil in a casserole to max 80°C.", "Add mushrooms, garlic, thyme, and spices — the mushrooms must be fully covered by the oil.", "Hold at a constant temperature and let steep about 20–30 minutes, until the mushrooms are soft but still have some bite."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Roasted Cauliflower, Brown Butter, Yuzu & Sunflower Seeds', NULL, 'Meat & Mains', 'Easy', NULL, '25 min', NULL, NULL, NULL, '[{"type": "table", "heading": "Plate", "rows": [["Cauliflower, roasted", "150 g"], ["Yuzu-nut butter", "50 ml"], ["Sunflower seeds, roasted", "10 g"], ["Chives", "to taste"]]}, {"type": "table", "heading": "Yuzu-Nut Butter", "rows": [["Butter", "200 g"], ["Yuzu juice", "40 ml"], ["Light miso paste", "30 g"], ["Maple syrup", "15 g"]]}, {"type": "steps", "heading": "Method", "items": ["Yuzu-nut butter: cook the butter over medium heat until the milk solids turn golden brown and it smells nutty (beurre noisette).", "Remove from heat and whisk in the yuzu juice, light miso paste, and maple syrup until combined.", "Cut the cauliflower into florets, toss with oil and salt, and roast at high heat (220°C) until deeply golden and tender, about 20–25 minutes.", "Plate the roasted cauliflower, spoon over the warm yuzu-nut butter.", "Finish with toasted sunflower seeds and a scatter of chopped chives."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Green Curry Bowl (Assembly)', 'Per portion — build from other base recipes', 'Meat & Mains', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Portion", "rows": [["Jasmine rice, cooked", "180 g"], ["Green curry sauce (Kari omáčka)", "150 g"], ["Hokkaido squash, roasted", "40 g"], ["Broccoli, roasted", "35 g"], ["Courgette, roasted", "35 g"], ["Sweet potato, roasted", "40 g"], ["Crispy fried shallots", "8 g"], ["Amazu-pickled onion", "15 g"], ["Single-clove garlic, thinly sliced and fried", "5 g"], ["Chilli oil", "5 g"], ["Spring onion, sliced", "3 g"], ["Coriander leaves", "2 g"]]}, {"type": "steps", "heading": "Assembly", "items": ["Spoon warm jasmine rice into the bowl base.", "Ladle green curry sauce over the rice.", "Arrange the roasted vegetables (squash, broccoli, courgette, sweet potato) over the curry.", "Top with crispy shallots, pickled onion, and fried garlic.", "Finish with a drizzle of chilli oil, sliced spring onion, and coriander leaves."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Beetroot Gyoza Filling', 'Fills ~5 gyoza (15g each) — scale up as needed', 'Meat & Mains', 'Easy', NULL, '10 min', '1 hr', NULL, NULL, '[{"type": "table", "heading": "Filling", "rows": [["Beetroot, roasted and grated", "60 g"], ["Firm tofu, pressed and crumbled", "25 g"], ["Spring onion, finely chopped", "10 g"], ["Garlic, finely grated", "1 g"], ["Ginger, finely grated", "2 g"], ["Shiitake, finely diced (fresh or rehydrated)", "10 g"], ["Soy sauce", "5 g"], ["Sesame oil", "3 g"], ["Potato starch or panko (binder)", "5 g"], ["Salt and white pepper", "to taste"]]}, {"type": "table", "heading": "To assemble", "rows": [["Gyoza wrappers", "5 pcs"], ["Filling", "15 g per gyoza"]]}, {"type": "steps", "heading": "Method", "items": ["Roast the beetroot whole, wrapped in foil, at 180°C until a knife slides in easily (about 45–60 minutes). Cool, peel, and grate coarsely.", "Press the tofu between paper towels for 10 minutes to remove excess moisture, then crumble finely.", "Sauté the shiitake, garlic, and ginger briefly in a little sesame oil until fragrant; cool.", "Combine grated beetroot, crumbled tofu, cooked shiitake mixture, spring onion, soy sauce, and remaining sesame oil in a bowl.", "Mix in the starch or panko to bind and firm up the texture — the filling should hold together when pressed, not be wet.", "Season with salt and white pepper to taste. Chill the filling for at least 20 minutes before filling wrappers, so it''s easier to portion.", "Place 15g of filling in the centre of each wrapper, wet the edge with water, fold in half, and pleat to seal.", "Pan-fry flat side down until golden, add a splash of water, cover to steam through, then uncover to crisp the base again before serving."]}, {"type": "text", "text": "Note: this filling recipe was reconstructed to fill the gap in the original costing sheet (which only recorded the 15g fill weight, not the composition) — adjust ratios to match the version actually served in the kitchen."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Fried Rice — Wok Technique', 'Per portion', 'Meat & Mains', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Per Portion", "rows": [["Day-old cooked rice, cold and separated", "220 g"], ["Neutral oil, high smoke point", "15 g"], ["Garlic, minced", "5 g"], ["Ginger, minced", "3 g"], ["Spring onion, sliced", "10 g"], ["Egg", "1"], ["Protein of choice (chicken, shrimp, char siu, etc.)", "80 g"], ["Mixed vegetables (peas, carrot, corn), diced", "40 g"], ["Soy sauce", "12 g"]]}, {"type": "steps", "heading": "Method", "items": ["Get the wok very hot before adding the oil — this is the key to good wok hei (smoky flavour).", "Scramble the egg quickly, remove, and set aside.", "Stir-fry the garlic and ginger briefly, then add the protein and vegetables in order of cooking time needed.", "Add the cold rice, breaking up any clumps with the back of the spatula, tossing constantly to coat in oil and heat evenly.", "Return the egg, season with soy sauce poured around the edge of the wok (not directly onto the rice) so it flash-cooks.", "Toss in the spring onion, cook a final minute, and serve immediately."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Katsu — Panko Breading & Frying Technique', 'Per portion', 'Meat & Mains', 'Easy', NULL, '4 min', NULL, NULL, NULL, '[{"type": "table", "heading": "Per Portion", "rows": [["Cutlet (pork, chicken, or firm fish)", "180 g"], ["Flour, seasoned with salt and pepper", "30 g"], ["Egg, beaten", "1"], ["Panko breadcrumbs", "50 g"], ["Frying oil, for deep-frying at 170–175°C", "1 L (fryer volume, reusable)"]]}, {"type": "steps", "heading": "Method", "items": ["Pound the cutlet to an even thickness.", "Pat dry, season, then dredge in flour, shaking off excess.", "Dip in beaten egg, letting excess drip off.", "Press into panko firmly and evenly on both sides — panko''s coarse texture is what gives katsu its signature crunch.", "Fry at 170–175°C until deep golden, turning once, about 3–4 minutes per side depending on thickness.", "Rest on a rack briefly, then slice into strips before serving with katsu sauce."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Wonton Dough & Filling Technique', 'Makes ~40 wontons', 'Meat & Mains', 'Easy', 'Makes 40 wontons', '5 min', '30 min', NULL, NULL, '[{"type": "table", "heading": "Dough (if not using store-bought wrappers)", "rows": [["Plain flour", "250 g"], ["Egg", "1"], ["Water", "60 ml"], ["Salt", "2 g"]]}, {"type": "table", "heading": "Classic Pork & Prawn Filling", "rows": [["Pork mince", "200 g"], ["Prawns, chopped", "100 g"], ["Spring onion, finely chopped", "20 g"], ["Ginger, grated", "5 g"], ["Soy sauce", "10 g"], ["Sesame oil", "5 g"], ["Shaoxing wine", "10 g"], ["White pepper", "1 g"], ["Cornstarch", "5 g"]]}, {"type": "steps", "heading": "Method", "items": ["If making dough: knead flour, egg, water, and salt into a smooth, firm dough. Rest 30 minutes, then roll paper-thin and cut into 8cm squares.", "Filling: combine pork, prawns, spring onion, ginger, soy sauce, sesame oil, Shaoxing wine, pepper, and cornstarch. Mix vigorously in one direction until the mixture becomes slightly sticky and cohesive.", "Place ~10g of filling in the centre of each wrapper.", "Wet the edges, fold into a triangle, then bring the two bottom corners together and pinch to seal, forming the classic wonton shape.", "Cook in gently simmering water or soup for 4–5 minutes until they float and the filling is cooked through."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Steamed Bao Dough', 'Makes ~12 buns', 'Meat & Mains', 'Easy', 'Makes 12 buns', '12 min', '1 hr', NULL, NULL, '[{"type": "table", "rows": [["Plain flour", "300 g"], ["Cornstarch", "20 g"], ["Sugar", "30 g"], ["Instant yeast", "4 g"], ["Baking powder", "4 g"], ["Milk, lukewarm", "160 ml"], ["Neutral oil", "15 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk flour, cornstarch, sugar, and yeast together.", "Add lukewarm milk and oil, knead into a smooth, soft dough, about 8–10 minutes by hand or 5 minutes in a mixer.", "Cover and proof in a warm place until doubled, about 1 hour.", "Knock back, knead in the baking powder, then divide into 12 pieces and shape into balls or folded buns.", "Rest on parchment squares 15–20 minutes to proof again.", "Steam over simmering water for 10–12 minutes. Keep the lid slightly ajar for the first minute after steaming to prevent collapsing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Course 3 — Noodle Dough', NULL, 'Meat & Mains', 'Easy', NULL, '3 min', '30 min', NULL, NULL, '[{"type": "table", "rows": [["Egg yolks", "9"], ["Whole eggs", "3"], ["00 flour", "280 g"], ["Semolina", "280 g"], ["Shitake powder", "40 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine the egg yolks and whole eggs, whisk lightly to break them up.", "Mix the 00 flour, semolina, and shitake powder together in a large bowl or on a work surface, forming a well in the centre.", "Pour the eggs into the well and gradually incorporate the flour, mixing with a fork or your hands until a shaggy dough forms.", "Knead for 8–10 minutes until smooth and elastic. Wrap tightly and rest at room temperature for at least 30 minutes.", "Roll thin (by hand or pasta machine) and cut into the desired noodle shape.", "Cook in well-salted boiling water for 2–3 minutes until just tender, depending on thickness."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'House BBQ Dry Rub', 'Base rub for ribs, pulled pork, and brisket — yields ~250 g', 'Meat & Mains', 'Easy', 'Yields ~250 g', NULL, '1 hr', NULL, NULL, '[{"type": "table", "rows": [["Brown sugar", "80 g"], ["Paprika (sweet)", "40 g"], ["Salt, fine", "30 g"], ["Black pepper, coarse ground", "20 g"], ["Garlic powder", "15 g"], ["Onion powder", "15 g"], ["Smoked paprika", "15 g"], ["Cayenne pepper", "5 g"], ["Mustard powder", "5 g"], ["Cumin, ground", "5 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk all ingredients together thoroughly, breaking up any clumps of brown sugar.", "Store in an airtight container, away from light — keeps well for several months.", "Apply generously to meat at least 1 hour before cooking, ideally overnight refrigerated (uncovered, to help form a bark)."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'House BBQ Sauce', 'Yields ~800 ml', 'Meat & Mains', 'Easy', 'Yields ~800 ml', '20 min', '20 min', NULL, NULL, '[{"type": "table", "rows": [["Ketchup", "400 g"], ["Apple cider vinegar", "80 ml"], ["Brown sugar", "80 g"], ["Molasses", "30 g"], ["Worcestershire sauce", "20 ml"], ["Dijon mustard", "20 g"], ["Smoked paprika", "10 g"], ["Garlic powder", "5 g"], ["Onion powder", "5 g"], ["Black pepper", "2 g"], ["Hot sauce (optional)", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all ingredients in a pot and whisk together.", "Bring to a gentle simmer, stirring occasionally to prevent catching on the bottom.", "Simmer 15–20 minutes until slightly thickened and the flavours have married.", "Cool and store refrigerated — keeps for several weeks. Use as a glaze in the final 15–20 minutes of cooking (it will burn if applied too early) or as a table sauce."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'BBQ Pork Spare Ribs', 'Serves 4 — low & slow, ~5–6 hrs total', 'Meat & Mains', 'Easy', 'Serves 4', '3 hr', '1 hr', NULL, NULL, '[{"type": "table", "rows": [["Pork spare ribs, membrane removed", "1.8 kg (1 full rack)"], ["House BBQ dry rub", "60 g"], ["Apple juice (for spritzing)", "200 ml"], ["House BBQ sauce, for glazing", "150 g"]]}, {"type": "steps", "heading": "Method", "items": ["Remove the thin membrane from the bone side of the rack — this lets smoke and seasoning penetrate and keeps the ribs from being chewy underneath.", "Coat the ribs generously on both sides with the dry rub, patting it in. Rest at least 1 hour, ideally overnight refrigerated, uncovered.", "Set up the smoker/grill for indirect heat at 110–120°C. Add wood chunks (apple or hickory work well) for smoke.", "Smoke the ribs bone-side down for about 3 hours, spritzing with apple juice every 45 minutes to keep the surface moist.", "Wrap the ribs tightly in foil with a splash of apple juice (the \"Texas crutch\") and return to the smoker for a further 1.5–2 hours, until a probe slides through the meat with no resistance.", "Unwrap, brush generously with BBQ sauce, and return to the smoker uncovered for 20–30 minutes to set the glaze and firm the bark back up.", "Rest 10 minutes before slicing between the bones."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pulled Pork Shoulder', 'Serves 10–12 — low & slow, ~10–12 hrs total', 'Meat & Mains', 'Medium', 'Serves 10–12', '7 hr', '5 hr', NULL, NULL, '[{"type": "table", "rows": [["Pork shoulder (Boston butt), bone-in", "3.5 kg"], ["House BBQ dry rub", "150 g"], ["Yellow mustard (as a binder, before the rub)", "40 g"], ["Apple juice (for spritzing)", "300 ml"], ["House BBQ sauce, to finish", "200 g"]]}, {"type": "steps", "heading": "Method", "items": ["Pat the pork shoulder dry. Rub the surface all over with mustard as a binder (it cooks off and won''t taste like mustard — it just helps the rub stick).", "Coat generously and evenly with the dry rub on all sides, pressing it in. Rest at least 2 hours, ideally overnight refrigerated.", "Set up the smoker for indirect heat at 110–120°C. Place the shoulder fat-side up and smoke, spritzing with apple juice every hour after the first 3 hours.", "Smoke until the internal temperature reaches about 74°C and a dark bark has formed, roughly 6–7 hours — this is the \"stall\" zone where temperature can plateau for hours; be patient, don''t raise the heat.", "Wrap tightly in butcher paper or foil once the bark is set, and continue cooking until the internal temperature reaches 96–98°C and a probe inserts with almost no resistance, a further 3–5 hours.", "Rest, still wrapped, in a cooler or warm oven (turned off) for at least 1 hour — this step is essential for a moist result.", "Unwrap, remove the bone (it should slide out cleanly), and shred the meat with two forks or claws, discarding excess fat.", "Toss the shredded pork with a little BBQ sauce and some of the rendered cooking juices to keep it moist. Serve with extra sauce on the side."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Smoked Beef Brisket', 'Serves 12–14 — low & slow, ~12–14 hrs total', 'Meat & Mains', 'Medium', 'Serves 12–14', '8 hr', '6 hr', NULL, NULL, '[{"type": "table", "rows": [["Beef brisket, whole (point + flat), trimmed", "5 kg"], ["Coarse salt", "50 g"], ["Coarse black pepper", "50 g"], ["Garlic powder", "15 g"]]}, {"type": "steps", "heading": "Method", "items": ["Trim the fat cap to an even 6–8mm thickness, removing any hard fat and silver skin.", "Season generously and evenly with salt, pepper, and garlic powder on all sides — Texas-style brisket keeps the rub simple to let the beef and smoke speak.", "Rest at least 1 hour at room temperature before smoking, or overnight refrigerated.", "Set up the smoker for indirect heat at 110–120°C with oak or hickory. Place the brisket fat-side up, point end toward the heat source if using an offset smoker.", "Smoke undisturbed until the internal temperature reaches about 70°C and a deep bark has formed, roughly 6–8 hours.", "Wrap tightly in butcher paper once the bark is set and colour is right, and continue cooking until internal temperature reaches 95–97°C and it probes like warm butter — a further 4–6 hours.", "Rest, still wrapped, in a cooler or warm oven (turned off) for at least 1–2 hours before slicing — this is critical for juiciness.", "Slice the flat against the grain into pencil-width slices; the point can be cubed and returned to the smoker briefly for burnt ends."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Classic Italian Porchetta (Rolled Pork Belly)', 'Serves 10–12 — roast ~3 hrs', 'Meat & Mains', 'Medium', 'Serves 10–12', '2.5 hr', '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Pork belly, skin-on, boned and butterflied", "2.5 kg"], ["Garlic, minced", "30 g"], ["Fresh rosemary, chopped", "15 g"], ["Fresh sage, chopped", "10 g"], ["Fennel seeds, toasted and crushed", "15 g"], ["Lemon zest", "2 lemons"], ["Chilli flakes", "3 g"], ["Olive oil", "30 g"], ["Coarse salt", "40 g"], ["Black pepper", "10 g"], ["Butcher''s twine", "as needed"]]}, {"type": "steps", "heading": "Method", "items": ["Lay the pork belly skin-side down. Score the meat side lightly in a crosshatch (not through to the skin).", "Mix garlic, rosemary, sage, fennel seeds, lemon zest, chilli flakes, and olive oil into a paste. Rub evenly over the meat side, leaving the skin clean.", "Season the meat side with half the salt and the pepper.", "Roll the belly tightly into a cylinder, skin-side out, and tie firmly with butcher''s twine at 2–3cm intervals.", "Score the skin in a fine crosshatch pattern, being careful not to cut into the meat. Rub the remaining salt over the skin.", "Rest uncovered in the fridge for at least 4 hours, ideally overnight — this dries the skin for better crackling.", "Roast at 220°C for 30–40 minutes to blister the skin, then reduce to 150°C and roast a further 2–2.5 hours until the internal temperature reaches 68–70°C.", "If the skin isn''t fully crisp, increase the heat back to 220–230°C for a final 10–15 minutes, watching closely.", "Rest 20 minutes before slicing into rounds."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Asian Five-Spice Rolled Pork Belly', 'Serves 8–10 — roast ~2.5 hrs', 'Meat & Mains', 'Medium', 'Serves 8–10', '2 hr', '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Pork belly, skin-on, boned and butterflied", "2 kg"], ["Spring onion, chopped", "40 g"], ["Ginger, grated", "20 g"], ["Garlic, minced", "20 g"], ["Five-spice powder", "8 g"], ["Soy sauce", "30 g"], ["Shaoxing wine", "20 g"], ["Sesame oil", "10 g"], ["Sugar", "15 g"], ["Coarse salt (for skin)", "30 g"], ["Butcher''s twine", "as needed"]]}, {"type": "steps", "heading": "Method", "items": ["Lay the pork belly skin-side down. Combine spring onion, ginger, garlic, five-spice, soy sauce, Shaoxing wine, sesame oil, and sugar into a paste.", "Spread the paste evenly over the meat side, leaving the skin clean and dry.", "Roll tightly into a cylinder, skin-side out, and tie firmly with butcher''s twine.", "Score the skin in a fine crosshatch, pat completely dry, and rub the coarse salt over the surface.", "Rest uncovered in the fridge at least 4 hours, ideally overnight, to dry the skin.", "Roast at 220°C for 30 minutes to start blistering the skin, then reduce to 160°C and roast a further 1.5–2 hours until internal temperature reaches 68–70°C.", "Brush off excess salt crust from the skin if needed, increase heat to 230°C for a final 10 minutes to fully crisp.", "Rest 15–20 minutes before slicing. Serve with steamed buns, cucumber, and hoisin, or sliced over rice."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Crispy Skin Roast Pork Belly (Siu Yuk)', 'Serves 6–8 — not rolled, flat roast', 'Meat & Mains', 'Medium', 'Serves 6–8', '45 min', '6 hr', NULL, NULL, '[{"type": "table", "rows": [["Pork belly, skin-on, flat piece", "1.5 kg"], ["Five-spice powder", "5 g"], ["Salt (for meat side)", "10 g"], ["White pepper", "2 g"], ["Shaoxing wine", "15 g"], ["Coarse rock salt (for skin)", "80 g"], ["White vinegar", "10 g"], ["Baking soda (rubbed into skin)", "5 g"]]}, {"type": "steps", "heading": "Method", "items": ["Score the skin in tight parallel lines, cutting through the skin but not into the fat/meat below.", "Flip and season the meat side with five-spice, salt, white pepper, and Shaoxing wine, rubbing it in well. Keep the skin completely dry and free of seasoning.", "Pat the skin dry, rub with white vinegar, then rub in the baking soda — this helps draw out moisture and encourages blistering.", "Rest uncovered in the fridge, skin exposed, for at least 6 hours, ideally overnight.", "Before roasting, brush off the baking soda residue and pat the skin fully dry. Cover the skin evenly with a layer of coarse rock salt (this insulates it during the first roast).", "Roast at 200°C for 45 minutes. Remove, brush off the hardened salt crust completely.", "Increase oven to 230–240°C and roast a further 25–35 minutes until the skin is fully puffed, golden, and crackling — watch closely and rotate if needed for even blistering.", "Rest 10 minutes, then chop into bite-sized pieces through the crackling with a heavy cleaver."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Char Siu Pork Belly', 'Serves 6 — uses House Char Siu Glaze', 'Meat & Mains', 'Easy', 'Serves 6', '20 min', '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Pork belly, skin removed, sliced into long strips", "1.5 kg"], ["Char siu glaze (see recipe)", "200 g"], ["Honey, for final baste", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Marinate the pork belly strips in two-thirds of the char siu glaze for at least 4 hours, ideally overnight, refrigerated.", "Set up a roasting rack over a water-filled tray (to catch drips and keep the oven clean) and hang or lay the strips.", "Roast at 200°C for 20 minutes, then baste with the remaining glaze and continue roasting a further 15–20 minutes until the internal temperature reaches 68–70°C and the edges are caramelized.", "Brush with a thin layer of honey in the final 5 minutes for extra shine.", "Rest 10 minutes, then slice thickly across the grain."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Rolled Stuffed Pork Loin (Braciole-Style)', 'Serves 6', 'Meat & Mains', 'Medium', 'Serves 6', '45 min', '10 min', NULL, NULL, '[{"type": "table", "rows": [["Pork loin, butterflied and pounded flat", "1.2 kg"], ["Prosciutto, thin slices", "100 g"], ["Provolone or fontina, sliced", "100 g"], ["Breadcrumbs", "40 g"], ["Parmesan, grated", "30 g"], ["Parsley, chopped", "10 g"], ["Garlic, minced", "10 g"], ["Pine nuts, toasted", "20 g"], ["Raisins, soaked", "20 g"], ["Olive oil", "20 g"], ["Salt and pepper", "to taste"], ["Butcher''s twine", "as needed"]]}, {"type": "steps", "heading": "Method", "items": ["Lay the pounded pork loin flat, season with salt and pepper.", "Layer the prosciutto and cheese evenly over the surface, leaving a small border.", "Mix breadcrumbs, parmesan, parsley, garlic, pine nuts, and raisins with a little olive oil to bind. Scatter evenly over the prosciutto and cheese layer.", "Roll tightly from one end, tie with butcher''s twine at regular intervals to hold its shape.", "Sear the rolled loin in a hot pan with olive oil on all sides until browned.", "Transfer to a 180°C oven and roast until internal temperature reaches 63°C, about 35–45 minutes depending on thickness.", "Rest 10 minutes before removing the twine and slicing into rounds."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Soya Caramel Sauce', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, '20 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Soy sauce", "200 ml"], ["Rice vinegar", "200 ml"], ["Garlic cloves", "12"], ["Shallots, medium", "6"], ["Honey", "6 tbsp"], ["Cream", "3–4 L"], ["Black pepper", "to taste"]]}, {"type": "text", "text": "Method not written out in the notes — appears to be combined and reduced to a caramel-style sauce."}, {"type": "steps", "heading": "Method", "items": ["Peel the garlic cloves and shallots; smash the garlic lightly to release its oils.", "Combine soy sauce, rice vinegar, garlic, shallots, and honey in a pot.", "Bring to a simmer and cook gently for 15–20 minutes until the shallots and garlic are very soft and the liquid has reduced slightly.", "Stir in the cream and continue simmering, stirring occasionally, until the sauce thickens to a light caramel consistency that coats the back of a spoon.", "Season with black pepper to taste. Blend smooth if a silkier texture is wanted, or leave rustic with the softened garlic and shallot pieces intact."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Lamb Reduction', 'Jahňacia redukcia', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, '8 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Lamb trim/offcuts", "5 kg"], ["Lamb bones", "10 kg"], ["Water", "30–40 L"], ["Onion", "4"], ["Carrot", "4"], ["Leek", "2"], ["Bay leaf", "5"], ["Allspice", "1/2 tbsp"], ["Garlic (heads)", "2"], ["Olive oil", "as needed"]]}, {"type": "steps", "heading": "Method", "items": ["Roast the lamb trim in the oven.", "Wash, dry, and cut the vegetables into large pieces; grill.", "Put everything into a large pot, bring to a boil, and simmer 6–8 hours.", "Strain, then reduce down to roughly 1/10th of the original volume."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Final Sauce (for Lamb Reduction)', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Lamb reduction", "5 L"], ["Lemongrass", "4 stalks"], ["Red finger chilli", "4"], ["Small chilli", "1–2"], ["Coriander stems", "30 g"], ["Thai basil stems", "30 g"], ["Spring onion", "2"], ["Kaffir lime leaves", "5"], ["Maltose", "1 piece"], ["Ginger", "30 g"], ["Galangal", "20 g"], ["Fish sauce", "to taste"]]}, {"type": "text", "text": "Method: Blend all aromatics in a Thermomix, add to the lamb reduction, and let infuse until the desired flavour and consistency are reached. Season with fish sauce to taste; store."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Vegan Kimchi Paste', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, '48 hr', NULL, NULL, '[{"type": "table", "rows": [["Ginger", "120 g (150 g whole)"], ["Spring onion", "120 g"], ["Garlic", "80 g"], ["Chilli (seeds in)", "50 g (2 pcs)"], ["Korean chilli", "50 g"], ["Thai chilli", "2 pcs"], ["Caster sugar", "20 g (50 g new)"], ["Maldon salt", "50 g (70 g new)"]]}, {"type": "steps", "heading": "Method", "items": ["Roughly chop the ginger, spring onion, and garlic.", "Blend the ginger, spring onion, garlic, both chillies, and Korean chilli together with a splash of water into a coarse paste.", "Stir in the caster sugar and Maldon salt until dissolved into the paste.", "Use to season shredded cabbage or other vegetables for a quick vegan kimchi — massage the paste in thoroughly and let ferment/marinate at room temperature for 24–48 hours before refrigerating."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Thai Red Curry', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Curry Paste (yields 2.80 kg)", "rows": [["Lemongrass, frozen", "1.00 kg"], ["Galangal, frozen", "0.80 kg"], ["Garlic", "0.25 kg"], ["Small chilli", "0.08 kg"], ["Yellow onion", "0.35 kg"], ["Coriander", "0.15 kg"], ["Lime leaves, frozen", "0.05 kg"], ["Rapeseed oil", "0.15 L"], ["Water", "0.15 L"], ["Ground red paprika", "0.03 kg"]]}, {"type": "table", "heading": "Curry (yields 3 L)", "rows": [["Coconut milk", "3 L"], ["Curry paste (above)", "0.60 kg"], ["Lime", "0.30 kg"], ["Palm sugar", "0.45 kg"], ["Fish sauce", "0.10 L"], ["Green SOSA colouring", "3 g"]]}, {"type": "steps", "heading": "Method", "items": ["Curry paste: blend lemongrass, galangal, garlic, chilli, onion, coriander, lime leaves, oil, water, and ground paprika together into a smooth, fragrant paste.", "Fry the paste in a splash of oil over medium heat for several minutes until it darkens slightly and smells fragrant, rather than raw.", "Curry: warm the coconut milk in a pot, whisk in the fried curry paste, and bring to a gentle simmer.", "Add lime, palm sugar, and fish sauce, stirring until the sugar dissolves.", "Stir in the green SOSA colouring if using. Simmer a few minutes to marry the flavours, then adjust seasoning with more fish sauce, sugar, or lime as needed."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Curry Spice Mix', 'For curry paste base — 140 g rice/portion', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Chicken", "3 kg"], ["Lemongrass", "2 kg"], ["Lime leaf", "100 g"], ["Galangal", "350 g"], ["Garlic", "250 g"], ["Cinnamon", "130 g"], ["Star anise", "70 g"], ["Cloves", "10 g"], ["Cardamom", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Roughly chop the lemongrass, lime leaf, galangal, and garlic.", "Toast the cinnamon, star anise, cloves, and cardamom briefly in a dry pan until fragrant.", "Blend all the aromatics together with the toasted spices into a coarse paste or fine mix, depending on how it will be used.", "Use to season the chicken and rice base for the curry, or fry off in oil first to build a deeper flavour before adding liquid."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Mushroom Butter', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Grilled shitake mushrooms", "60 g"], ["Butter, room temperature", "80 g"], ["Truffle essence", "4 g (or to taste)"], ["White miso", "9 g"]]}, {"type": "steps", "heading": "Method", "items": ["Finely chop the grilled shitake mushrooms.", "Beat the softened butter until smooth and light.", "Mix in the chopped shitake, truffle essence, and white miso until evenly combined.", "Roll into a log in cling film, twist the ends to seal, and chill until firm.", "Slice into discs to melt over grilled fish, vegetables, or rice."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Café de Paris Butter', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Butter", "750 g"], ["Shallots", "50 g"], ["Garlic", "20 g"], ["Anchovy fillets", "30 g"], ["Capers", "20 g"], ["Curry powder", "10 g"], ["Sweet paprika", "10 g"], ["Fresh tarragon", "15 g"], ["Fresh parsley", "15 g"], ["Cognac", "20 g"], ["Dijon mustard", "20 g"], ["Worcestershire sauce", "10 g"], ["Lemon juice", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Bring the butter to room temperature so it''s soft and easy to work.", "Finely mince shallots, garlic, anchovy, capers, tarragon, and parsley.", "Beat the softened butter until smooth, then mix in all the chopped aromatics, spices, cognac, mustard, Worcestershire, and lemon juice until fully combined.", "Taste and adjust seasoning — it should be punchy, since it''s served cold and melts over hot protein.", "Roll into a log in cling film or parchment, twist the ends to seal, and chill until firm.", "Slice into discs to serve on top of grilled meat or fish straight off the heat."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Truffle Mayonnaise', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Mayonnaise (base)", "850 g"], ["Truffle paste (Tartufata)", "100 g"], ["White truffle oil", "15 g"], ["Sherry vinegar", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk the truffle paste into the mayonnaise base until fully combined and smooth.", "Stream in the white truffle oil while whisking to emulsify evenly.", "Whisk in the sherry vinegar to brighten and balance the richness.", "Taste and adjust — truffle oil strength varies by brand, so add gradually.", "Chill before serving; store in a sealed container."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chipotle Dip', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Sour cream", "500 g"], ["Mayonnaise", "300 g"], ["Chipotle in adobo", "100 g"], ["Lime juice, fresh", "30 g"], ["Coriander stems", "15 g"], ["Salt", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Finely chop the chipotle in adobo and the coriander stems.", "Whisk sour cream and mayonnaise together until smooth.", "Fold in the chopped chipotle, adobo sauce, and coriander stems.", "Add lime juice and salt, mix well, and taste — adjust heat by adding more or less chipotle.", "Chill before serving to let the flavours settle."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chimichurri', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, '30 min', NULL, NULL, '[{"type": "table", "rows": [["Parsley", "170 g"], ["Garlic, degermed", "100 g"], ["Peperoncini, deseeded", "4 pcs"], ["Condimento balsamico", "100 ml"], ["Dried oregano, rehydrated", "35 g"], ["Dried thyme, rehydrated", "35 g"], ["Olive oil", "500 ml"], ["Salt", "70 g"], ["Pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Rehydrate the dried oregano and thyme in a little warm water until softened; drain well.", "Finely chop parsley, garlic, and peperoncini by hand for the best texture — a food processor can turn it to mush.", "Combine the chopped herbs, garlic, peperoncini, and rehydrated oregano/thyme in a bowl.", "Stir in the balsamic condimento and olive oil.", "Season with salt and pepper, mix well, and let rest at room temperature for at least 30 minutes before serving so the flavours infuse.", "Store refrigerated; bring back to room temperature before serving so the oil isn''t solid."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Kari Pasta (Spiced Curry Paste)', 'Large batch ≈ 5.9 kg — scale down as needed', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, 56.28, 8.79, '[{"type": "table", "rows": [["Spring onion", "3 kg"], ["Lemongrass", "2 kg"], ["Lime leaves", "100 g"], ["Galangal", "350 g"], ["Garlic", "250 g"], ["Cinnamon", "130 g"], ["Cardamom", "80 g"], ["Cloves", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Roughly chop spring onion, lemongrass, and galangal.", "Toast cinnamon, cardamom, and cloves briefly to wake up their aromatics.", "Blend all ingredients together (food processor or Thermomix) into a coarse, fragrant paste.", "Use as the aromatic base for a Kari (curry) sauce — sweat the paste in oil before adding stock and coconut milk."]}, {"type": "text", "text": "Note: this is a bulk-batch paste (~5.9 kg). For a home or small-service batch, scale all quantities down proportionally, e.g. by 1/10th."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Karamelizovaná Cibuľa (Caramelized Onion, Asian-Style)', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, 7.3, 3.58, '[{"type": "table", "rows": [["Red onion", "700 g"], ["White onion", "700 g"], ["Shallot", "150 g"], ["Red chilli", "50 g"], ["Ginger", "90 g"], ["Garlic", "40 g"], ["Soy sauce", "320 g"], ["Sake", "320 g"], ["Rice vinegar (Suehiro)", "320 g"], ["Sugar", "350 g"]]}, {"type": "steps", "heading": "Method", "items": ["Slice onions, shallot, chilli, ginger, and garlic thinly.", "Sweat slowly in a wide pan until deeply softened and starting to caramelize.", "Deglaze with sake, then add soy sauce, rice vinegar, and sugar.", "Simmer gently until syrupy and jammy in consistency. Cool and store."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tom Yum Paste', 'Yields ≈ 1.2 kg', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, 8.68, 9.33, '[{"type": "table", "rows": [["Lemongrass", "300 g"], ["Lime leaves", "50 g"], ["Galangal", "150 g"], ["Yellow onion", "100 g"], ["Garlic", "50 g"], ["Coriander stems", "100 g"], ["Ginger", "100 g"], ["Red chilli", "45 g"], ["Ground paprika", "30 g"], ["Rapeseed oil", "300 g"]]}, {"type": "steps", "heading": "Method", "items": ["Roughly chop lemongrass, galangal, onion, garlic, coriander stems, ginger, and chilli.", "Blend everything with the ground paprika and oil into a coarse, fragrant paste.", "Cook gently in a pot for a few minutes to mellow the raw edge, stirring so it doesn''t catch.", "Cool and store. Use as the base for tom yum soup — dilute with stock, season with fish sauce, lime, and sugar to taste."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tempura Batter & Frying Technique', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Ice-cold water", "200 ml"], ["Egg yolk", "1"], ["Tempura flour (or 00 flour + cornstarch)", "150 g"], ["Frying oil", "for deep-frying, ~170–180°C"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk egg yolk into ice-cold water.", "Add the flour all at once and mix with chopsticks in a few loose strokes — leave it lumpy, do not overmix (gluten development makes it heavy).", "Keep the batter over ice while frying.", "Pat ingredients dry, dust lightly with flour, then dip into batter and lower into 170–180°C oil.", "Fry until just pale golden and crisp — do not overcrowd the pot. Drain on a rack, not paper towel, to stay crisp."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Teriyaki Sauce', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Soy sauce", "100 ml"], ["Mirin", "100 ml"], ["Sake", "50 ml"], ["Sugar", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all ingredients in a pot.", "Bring to a simmer and reduce by about a third, until lightly syrupy enough to coat the back of a spoon.", "Cool and store; use as a glaze for grilled or pan-seared fish, chicken, or beef."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Yakitori Tare', 'Glazing sauce for grilled skewers', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, '30 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Soy sauce", "200 ml"], ["Mirin", "200 ml"], ["Sake", "100 ml"], ["Sugar", "50 g"], ["Chicken bones/wings (optional, for depth)", "300 g"]]}, {"type": "steps", "heading": "Method", "items": ["If using, roast the chicken bones/wings until golden.", "Combine all ingredients in a pot, bring to a boil, then simmer gently for 20–30 minutes until reduced and glossy.", "Strain out any bones. Cool.", "Brush onto skewers partway through grilling, then again just before serving — building layers rather than one thick coat."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Gyoza Dough & Folding Technique', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, '30 min', NULL, NULL, '[{"type": "table", "heading": "Dough", "rows": [["Plain flour", "250 g"], ["Boiling water", "130 ml"], ["Salt", "2 g"]]}, {"type": "steps", "heading": "Method", "items": ["Mix flour and salt, pour in boiling water while stirring with chopsticks.", "Once cool enough to handle, knead 8–10 minutes until smooth and elastic. Rest, covered, 30 minutes.", "Roll into a log, divide into ~10g pieces, roll each into a thin round (thinner at the edges, slightly thicker in the centre).", "Fill with ~15g of filling, wet the edge, fold in half, and pleat from one end to the other to seal.", "Pan-fry flat-side down until golden, add a splash of water, cover to steam, then uncover to crisp the base again."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chilli Oil (Rāyu)', NULL, 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Neutral oil", "300 ml"], ["Chilli flakes", "40 g"], ["Garlic, sliced", "20 g"], ["Ginger, sliced", "15 g"], ["Spring onion (white part)", "20 g"], ["Star anise", "1"], ["Sesame seeds", "1 tbsp"]]}, {"type": "steps", "heading": "Method", "items": ["Put chilli flakes and sesame seeds in a heatproof bowl.", "Heat the oil with garlic, ginger, spring onion, and star anise until the aromatics turn golden and the oil is fragrant (around 140–150°C).", "Strain the hot oil directly over the chilli flakes — it should sizzle. Stir well.", "Cool completely before bottling. Keeps for several weeks refrigerated."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chinese Master Stock (Lu Shui)', 'Reusable braising stock — yields ~3 L, base batch', 'Sauces, Marinades & Hot Basics', 'Easy', 'Yields ~3 L, base batch', NULL, '45 min', NULL, NULL, '[{"type": "table", "rows": [["Water", "3 L"], ["Soy sauce", "300 ml"], ["Dark soy sauce", "100 ml"], ["Shaoxing wine", "200 ml"], ["Rock sugar", "150 g"], ["Star anise", "6"], ["Cinnamon stick", "2"], ["Sichuan peppercorns", "15 g"], ["Ginger, sliced", "50 g"], ["Spring onion", "4 stalks"], ["Dried tangerine peel", "1 piece"], ["Bay leaves", "3"]]}, {"type": "steps", "heading": "Method", "items": ["Toast star anise, cinnamon, and Sichuan peppercorns briefly in a dry pot until fragrant.", "Add water, both soy sauces, Shaoxing wine, rock sugar, ginger, spring onion, tangerine peel, and bay leaves.", "Bring to a boil, then simmer 45 minutes to let the aromatics infuse fully.", "Strain and use to braise duck, pork belly, or eggs — simmer the protein directly in the stock until tender.", "Strain and refrigerate/freeze the stock after each use; it improves with age and can be reused indefinitely if boiled and topped up each time."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Char Siu Glaze', 'Yields enough for ~1.5 kg pork', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Hoisin sauce", "80 g"], ["Honey", "60 g"], ["Soy sauce", "40 g"], ["Shaoxing wine", "30 g"], ["Five-spice powder", "3 g"], ["Garlic, grated", "10 g"], ["Red fermented bean curd (nam yu), mashed", "15 g"], ["Maltose or extra honey", "20 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk all ingredients together until smooth.", "Marinate pork shoulder strips in two-thirds of the mixture for at least 4 hours, ideally overnight, refrigerated.", "Reserve the remaining glaze for basting.", "Roast the marinated pork at 200°C, basting with the reserved glaze every 10 minutes, until deeply caramelized and cooked through (internal 63°C+), about 25–30 minutes total.", "Rest 5 minutes before slicing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'XO Sauce', 'Yields ~500 g', 'Sauces, Marinades & Hot Basics', 'Easy', 'Yields ~500 g', '2 hr', '5 min', NULL, NULL, '[{"type": "table", "rows": [["Dried scallops, rehydrated and shredded", "60 g"], ["Dried shrimp, rehydrated and minced", "40 g"], ["Shallot, finely diced", "100 g"], ["Garlic, finely diced", "60 g"], ["Red chilli, finely diced (deseeded for less heat)", "80 g"], ["Jinhua ham or bacon, finely diced", "40 g"], ["Neutral oil", "250 ml"], ["Sugar", "15 g"], ["Soy sauce", "15 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Rehydrate dried scallops and shrimp in warm water for 1–2 hours, then shred/mince finely.", "Heat oil in a wok over medium-low heat, fry shallot and garlic slowly until golden and fragrant, being careful not to burn.", "Add the ham/bacon, fry until crisp.", "Add the shredded scallops and shrimp, fry gently for 10–15 minutes until deeply aromatic and slightly crisp at the edges.", "Add chilli, sugar, and soy sauce, cook a further 5 minutes.", "Cool and store in a sealed jar, submerged in the oil — keeps refrigerated for several weeks."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pad Thai Sauce', 'Yields ~300 ml', 'Sauces, Marinades & Hot Basics', 'Easy', 'Yields ~300 ml', '5 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Tamarind paste", "60 g"], ["Palm sugar", "80 g"], ["Fish sauce", "60 ml"], ["Water", "60 ml"], ["Rice vinegar", "15 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Warm the tamarind paste with water to loosen, then strain to remove any fibres/seeds.", "Combine tamarind liquid, palm sugar, fish sauce, and rice vinegar in a pot.", "Simmer gently, stirring, until the sugar fully dissolves and the sauce lightly thickens, about 5 minutes.", "Cool and taste — should balance sour, sweet, and salty. Adjust with more tamarind, sugar, or fish sauce.", "Toss through stir-fried rice noodles, egg, protein, and beansprouts just before serving."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Korean Bulgogi Marinade', 'For ~800g thinly sliced beef', 'Sauces, Marinades & Hot Basics', 'Easy', NULL, NULL, '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Soy sauce", "80 ml"], ["Sugar", "40 g"], ["Pear, grated (or apple)", "60 g"], ["Garlic, grated", "15 g"], ["Ginger, grated", "5 g"], ["Sesame oil", "20 ml"], ["Toasted sesame seeds", "10 g"], ["Black pepper", "2 g"], ["Spring onion, sliced", "20 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine soy sauce, sugar, grated pear, garlic, and ginger — the pear both sweetens and tenderizes the meat.", "Whisk in sesame oil, sesame seeds, and pepper.", "Toss with thinly sliced beef (ribeye or sirloin) and spring onion, massaging the marinade in.", "Marinate at least 30 minutes, ideally 2–4 hours refrigerated.", "Sear quickly over very high heat in batches — don''t overcrowd the pan, or the beef will steam instead of caramelize."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Glaze (2)', 'Cook base to 102°C', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Base", "rows": [["Water", "150 g"], ["Sugar", "300 g"], ["Glucose", "300 g"], ["Condensed milk", "200 g"], ["Vanilla pod", "1/2"], ["Gelatine", "21 g"], ["White chocolate", "330 g"], ["Water", "100 g"], ["Green/yellow colour", "to finish"]]}, {"type": "table", "heading": "Second mixture (added at the end)", "rows": [["Pear purée", "250 g"], ["Water", "187.5 g"], ["Gelatine", "8.5 leaves"]]}, {"type": "steps", "heading": "Method", "items": ["Cook water, sugar, and glucose to 102°C.", "Whisk in condensed milk and vanilla.", "Add bloomed gelatine.", "Pour hot mixture over white chocolate + water; mix until smooth. Add colour.", "Combine with the pear purée/water/gelatine mixture; mix everything together."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Glaze (1) — White Chocolate/Cocoa Butter', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["White chocolate", "250 g"], ["Cocoa butter", "250 g"]]}, {"type": "steps", "heading": "Method", "items": ["Melt together and mix."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Whisky Foam', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Milk", "600 g"], ["Cream", "150 g"], ["Sugar", "80 g"], ["Whisky", "80 g"], ["Gelatine", "2 leaves"]]}, {"type": "steps", "heading": "Method", "items": ["Heat milk, cream, and sugar together.", "Add whisky.", "Stir in bloomed gelatine leaves until dissolved."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pear Mousse', 'x2 batch', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Pear purée", "650 g"], ["Yuzu purée", "15 g"], ["Tonka beans", "2"], ["Cocoa butter", "120 g"], ["White chocolate", "120 g"], ["Gelatine (x3)", "6 g"], ["Xanthan gum", "4 g"], ["Cream", "200 g"], ["Mascarpone", "200 g"]]}, {"type": "steps", "heading": "Method", "items": ["Warm pear purée, yuzu purée, and tonka beans together.", "Bloom and dissolve gelatine into the warm purée.", "Melt cocoa butter and white chocolate together.", "Blend all together with xanthan gum.", "Fold in cream and mascarpone."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Green Tea Ice Cream', 'Heat to 85°C · yields ~2440 g', 'Plated Desserts', 'Easy', 'Yields ~2440 g', NULL, '55 min', NULL, NULL, '[{"type": "table", "rows": [["Water", "1000 g"], ["Cream", "444 g"], ["Milk powder", "235 g"], ["Dextrose powder", "104 g"], ["Glucose powder", "52 g"], ["Sugar", "392 g"], ["Stabilizer", "18 g"], ["Green tea powder", "47 g"], ["Hot water", "326 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine water and cream, warm.", "Whisk in milk powder, dextrose powder, and glucose powder (rest ~25 min).", "Add sugar and stabilizer; heat to 85°C (rest ~55 min).", "Bloom green tea powder in hot water, then stir in at the end. Chill and churn."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Vanilla Ice Cream', '85°C · yields ~2440 g', 'Plated Desserts', 'Easy', 'Yields ~2440 g', '25 min', '45 min', NULL, NULL, '[{"type": "table", "rows": [["Milk", "1235 g"], ["Cream", "395 g"], ["Milk powder", "70 g"], ["Trimoline", "40 g"], ["Egg yolk", "200 g"], ["Sugar (split in two)", "90 g"], ["Dextrose powder", "210 g"], ["Stabilizer", "14 g"], ["Vanilla pod", "2"]]}, {"type": "steps", "heading": "Method", "items": ["Combine milk and cream; heat.", "Add milk powder and trimoline (~25 min).", "Whisk egg yolks with half the sugar (~45°C base).", "Add dextrose powder, stabilizer, remaining sugar, and vanilla; cook to 85°C (~45 min rest). Chill and churn."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Yuzu Jelly', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Yuzu purée", "120 g"], ["Water", "80 g"], ["Sugar", "100 g"], ["Gelatine", "4 leaves"], ["Lemon-yellow colour", "to finish"]]}, {"type": "steps", "heading": "Method", "items": ["Combine yuzu purée and water.", "Stir in sugar.", "Add bloomed gelatine; add colour, set."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Frozen Nougat', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Almond praline (sugar/almond)", "75 g"], ["Caramelized pistachio", "40 g"], ["Egg white", "120 g"], ["Sugar", "60 g"], ["Water", "55 g"], ["Sugar (syrup, cook to 120°C)", "150 g"], ["Whipping cream", "600 g"], ["Cranberry compote", "120 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whip egg whites with the 60 g sugar to soft peaks.", "Cook the 150 g sugar with water to 120°C; pour into whipped egg whites to make an Italian meringue.", "Fold in the almond praline and caramelized pistachio.", "Fold in whipped cream and cranberry compote."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Coconut Marshmallow', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Trimoline", "60 g"], ["Trimoline", "50 g"], ["Sugar", "120 g"], ["Coconut milk", "35 g"], ["Gelatine", "11 g"]]}, {"type": "steps", "heading": "Method", "items": ["Cook the 50 g trimoline, sugar, and coconut milk to 115°C.", "Add bloomed gelatine, dissolve.", "Whip with the remaining 60 g trimoline until light and marshmallow-like in texture."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Kinako Crumble', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Butter (diced)", "500 g"], ["Sugar", "250 g"], ["Flour", "500 g"], ["Almond powder", "300 g"], ["Kinako (roasted soybean) powder", "200 g"]]}, {"type": "text", "heading": "Optional finish (crunch coating)", "text": "250 g baked crumble + white chocolate (Opalys) + 25 g milk powder, mixed together."}, {"type": "steps", "heading": "Method", "items": ["Rub butter, sugar, flour, almond powder, and kinako powder together into a crumble.", "Bake off until golden, cool.", "If desired, coat the baked crumble in melted Opalys and toss with milk powder for extra crunch/shelf life."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chocolate Financier', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Almond powder", "370 g"], ["Icing sugar", "240 g"], ["Corn flour", "30 g"], ["Cocoa powder", "20 g"], ["Brown butter", "150 g"], ["Trimoline", "60 g"], ["Egg white", "460 g"], ["Guanaja 70% chocolate", "170 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk egg whites with trimoline.", "Melt the Guanaja chocolate.", "Sift together almond powder, icing sugar, corn flour, and cocoa powder.", "Fold everything together with the brown butter."]}, {"type": "text", "heading": "Variation — Pumpkin Financier", "text": "Add 1 tsp cinnamon powder + 1 tsp pumpkin purée to the base batter."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Yuzu Crémeux', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Milk", "200 g"], ["Cream", "200 g"], ["Sugar", "80 g"], ["Egg yolk", "100 g"], ["Opalys (white chocolate)", "300 g"], ["Yuzu purée", "40 g"], ["Gelatine", "2 leaves"], ["Lemon-yellow colour", "to finish"]]}, {"type": "steps", "heading": "Method", "items": ["Heat milk and cream together.", "Whisk sugar and egg yolks; temper with the hot milk/cream (crème anglaise method).", "Pour the hot custard over the Opalys chocolate to melt.", "Stir in yuzu purée.", "Add bloomed gelatine and colour."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sago Pudding', 'Half batch shown', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Almond milk", "400 g"], ["Sago pearls", "50 g"], ["Sugar", "31 g"], ["Vanilla pod", "1/2"], ["Coconut milk", "100 g"]]}, {"type": "steps", "heading": "Method", "items": ["Cook almond milk with sago pearls until tender.", "Stir in sugar and vanilla.", "Add coconut milk and let cool (chill before serving)."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tofu Mousse', 'Use Sinoa · 24 hr set', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Tofu", "350 g"], ["Soya cream", "125 g"], ["Gelatine", "3 leaves"], ["Philadelphia cream cheese", "200 g"], ["Maple syrup", "75 g"]]}, {"type": "steps", "heading": "Method", "items": ["Blend tofu, Philadelphia, and maple syrup until smooth.", "Melt gelatine (microwave) and stir in.", "Whip soya cream to soft peaks and fold through."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sesame Tuile', '9 cm ring · 170°C / 3-speed fan / 8 min', 'Plated Desserts', 'Easy', NULL, '8 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Golden syrup", "500 g"], ["Soft brown butter", "600 g"], ["Sugar", "900 g"], ["Milk", "500 g"], ["Butter", "500 g"], ["Almond powder", "500 g"], ["Sesame seeds", "600 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine all ingredients into a smooth batter.", "Spread thinly using a 9 cm ring template.", "Bake at 170°C, 3-speed fan, for 8 minutes."]}, {"type": "text", "text": "Note: keep consistency controlled — batter should not be too runny."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sorbet Syrup (base)', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Sugar", "1 kg"], ["Glucose", "86 g"], ["Water", "866.5 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine and heat gently until dissolved; use as the base syrup for sorbets."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Manjari Financier Mix', '185°C / 4-speed fan / 12 min (check 10)', 'Plated Desserts', 'Easy', NULL, '12 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Butter", "420 g"], ["Manjari chocolate", "420 g"], ["Whole eggs", "8"], ["Egg yolks", "8"], ["Sugar", "250 g"], ["Kinako (fermented soy) powder", "50 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whip whole eggs and egg yolks together (stand mixer), adding sugar gradually in 3 additions.", "Melt butter and Manjari chocolate together.", "Fold the melted chocolate/butter into the whipped eggs.", "Fold in kinako powder. Bake at 185°C, 4-speed fan, 12 min (check at 10 min)."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Black Forest Mousse', NULL, 'Plated Desserts', 'Medium', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Base (x1)", "rows": [["Milk", "100 g"], ["Cream 35%", "100 g"], ["Illanka chocolate", "80 g"], ["Egg yolk", "40 g"], ["Sugar", "30 g"]]}, {"type": "text", "heading": "Scaled batch (x5)", "text": "Milk 500 g · Cream 500 g · Illanka 400 g · Egg yolk 200 g · Sugar 150 g"}, {"type": "steps", "heading": "Method", "items": ["Heat milk and cream.", "Whisk egg yolk and sugar; temper with the hot milk/cream to make a crème anglaise.", "Pour hot custard over Illanka chocolate to melt and emulsify."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chocolate Cookie House', '170°C / 3-speed fan / 7 min', 'Plated Desserts', 'Easy', NULL, NULL, '7 min', NULL, NULL, '[{"type": "table", "rows": [["Butter", "260 g"], ["Icing sugar", "170 g"], ["Almond powder", "50 g"], ["Eggs", "2"], ["Salt", "to taste"], ["Flour", "390 g"], ["Cocoa powder", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Cream butter with icing sugar.", "Beat in eggs.", "Fold in almond powder, flour, cocoa powder, and salt.", "Chill dough, roll, cut, and bake at 170°C, 3-speed fan, for 7 minutes."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Green Tea Popcorn', 'With Manjari chocolate', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Popcorn", "70 g"], ["Coconut oil", "70 g"]]}, {"type": "steps", "heading": "Method", "items": ["Pop corn in coconut oil, then coat with melted Manjari chocolate."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pistachio Ice Cream', '85°C · scoop after churning', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Milk", "1450 g"], ["Cream", "120 g"], ["Trimoline", "90 g"], ["Milk powder", "60 g"], ["Stabilizer", "15 g"], ["Sugar", "166 g"], ["Pistachio paste", "335 g"], ["Green colour", "to finish"]]}, {"type": "steps", "heading": "Method", "items": ["Combine milk and cream, heat.", "Whisk in trimoline and milk powder (~25°C step).", "Add stabilizer and sugar; cook to 85°C (~45°C step).", "Cool, then stir in pistachio paste and green colouring. Churn."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Illanka Crémeux', NULL, 'Plated Desserts', 'Medium', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "x1", "rows": [["Milk", "125 g"], ["Cream 35%", "125 g"], ["Sugar", "50 g"], ["Egg yolk", "50 g"], ["Illanka chocolate", "112.5 g"]]}, {"type": "table", "heading": "x2", "rows": [["Milk", "250 g"], ["Cream 35%", "250 g"], ["Sugar", "100 g"], ["Egg yolk", "100 g"], ["Illanka chocolate", "225 g"]]}, {"type": "steps", "heading": "Method", "items": ["Heat milk and cream to 85°C.", "Whisk sugar and egg yolk; temper with hot milk/cream.", "Pour over Illanka chocolate; emulsify until smooth."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tuile Mix', '170°C / 3-speed fan / 3–4 min', 'Plated Desserts', 'Easy', NULL, '4 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Soft butter", "400 g"], ["Icing sugar", "400 g"], ["Egg white", "400 g"], ["Flour", "400 g"]]}, {"type": "steps", "heading": "Method", "items": ["Mix with stand mixer (or soften butter in microwave 2–2.5 min first).", "Spread thin, bake at 170°C, 3-speed fan, 3–4 min."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chocolate Tuile', 'x2 batch · 170°C / 3-speed fan / 5 min', 'Plated Desserts', 'Easy', NULL, '5 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Icing sugar", "50 g (100 g x2)"], ["Flour", "40 g (80 g x2)"], ["Cocoa powder", "10 g (20 g x2)"], ["Egg white", "55 g (110 g x2)"]]}, {"type": "steps", "heading": "Method", "items": ["Mix to a smooth paste, spread into leaf shapes.", "Bake at 170°C, 3-speed fan, 5 min.", "While warm, shape/stick onto crispy rice base."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Japanese Šišky (Doughnuts)', 'Components 1, 3, 6, 7', 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Dough", "rows": [["Egg yolks", "2"], ["Sugar", "40 g"], ["Milk", "130 g"], ["Flour", "160 g"], ["Egg whites", "3"]]}, {"type": "table", "heading": "Miso Chocolate", "rows": [["Dark chocolate", "250 g"], ["Butter", "40 g"], ["Milk", "175 g"], ["Honey", "50 g"], ["White miso paste", "60 g"]]}, {"type": "table", "heading": "Raspberry Ganache", "rows": [["White chocolate", "200 g"], ["Cream", "200 g"], ["Egg yolk", "200 g"], ["Sugar", "35 g"], ["Glucose", "70 g"], ["Yuzu juice", "15 g"], ["Lime", "65 g"], ["Lemon (zest, infusion only)", "1"]]}, {"type": "table", "heading": "Yogurt Snow", "rows": [["Yogurt", "400 g"], ["Water", "600 g"], ["Granulated sugar", "300 g"], ["Lemon juice", "75 g"], ["Yogurt powder", "10 g"], ["Unspecified (likely stabilizer)", "10 g"]]}, {"type": "text", "text": "Method steps for assembling the doughnuts were not written out — only the component recipes above."}, {"type": "steps", "heading": "Method", "items": ["Dough: warm the milk slightly, whisk in the egg yolks and sugar. Fold in the flour to form a smooth batter, then fold in the whipped egg whites in two additions to lighten it.", "Rest the batter briefly, then pipe or spoon into hot oil at 170–175°C, frying in small batches until deep golden and cooked through, turning as needed. Drain on a rack.", "Miso chocolate: melt the dark chocolate and butter together, warm the milk with honey and whisk in the white miso paste, then combine both mixtures until smooth and glossy.", "Raspberry ganache: heat the cream, pour over the white chocolate to melt, whisk in the egg yolk mixture (cooked gently to a light custard first with sugar and glucose), then stir in yuzu juice and lime; infuse with lemon zest and strain.", "Yogurt snow: whisk yogurt, water, sugar, lemon juice, and yogurt powder together, then freeze in a shallow tray. Scrape with a fork once frozen to create light, snow-like crystals.", "Assemble: dip or fill the warm doughnuts with miso chocolate and raspberry ganache, top with a scoop of yogurt snow just before serving."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Paris Brest / Vence / Meringue', 'Plating notes', 'Plated Desserts', 'Easy', NULL, '26 min', NULL, NULL, NULL, '[{"type": "list", "heading": "Garnish elements", "items": ["12 garlic cloves (as written — please confirm)", "6 medium strawberries", "6 tbsp honey", "3–4 L cream", "Black pepper"]}, {"type": "list", "heading": "Paris Brest assembly", "items": ["Base: miso caramel + strawberry salsa, caramel-strawberry sorbet in the centre", "Top: milk chocolate ganache piped around the edge", "Join: dusted with icing sugar + almonds"]}, {"type": "text", "heading": "Vence (choux rings)", "text": "Bake at 180°C for 26 minutes."}, {"type": "table", "heading": "Meringue", "rows": [["Egg white", "30 g"], ["Granulated sugar", "70 g"], ["Icing sugar", "50 g"], ["Yuzu juice", "to taste"], ["Freeze-dried strawberry powder", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Vence (choux rings): pipe choux pastry into rings, bake at 180°C for 26 minutes until deep golden and fully dried out inside.", "Meringue: whip the egg white to soft peaks, gradually add the granulated sugar, then fold in the sifted icing sugar. Pipe small kisses and dry in a low oven; season the mixture with yuzu juice and freeze-dried strawberry powder before piping.", "Garnish: reduce the honey with the garlic and black pepper if using a savoury note, or omit for a purely sweet garnish — warm the strawberries and cream mixture as needed.", "Assemble the Paris Brest base with miso caramel and strawberry salsa, add a scoop of caramel-strawberry sorbet to the centre.", "Split the choux ring, pipe milk chocolate ganache around the top edge, and sandwich together.", "Dust the join with icing sugar and almonds, and finish with the meringue kisses just before serving."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Macarons', 'Italian meringue method', 'Plated Desserts', 'Easy', NULL, '8 min', '20 min', NULL, NULL, '[{"type": "table", "rows": [["Ground almond", "100 g"], ["Icing sugar", "100 g"], ["Egg white (paste)", "37 g"], ["Sugar (syrup)", "100 g"], ["Water", "33 g"], ["Egg white (to whip)", "5"]]}, {"type": "steps", "heading": "Method", "items": ["Mix ground almond, icing sugar, and 37 g egg white into a paste.", "Cook sugar and water to 117–121°C.", "Whip the 5 egg whites, starting speed 2.5, finishing 3.1 as hot syrup is added; whip to glossy stiff peaks.", "Fold syrup meringue into the almond paste until \"lava-like\" flowing consistency.", "Pipe and rest 15–20 minutes until skinned over.", "Preheat oven to 135°C; bake at 150°C for 5 min, then reduce to 145°C for 8 min, no fan."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Ganache — Mango-Passion', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Passion fruit purée", "200 g"], ["Mango purée", "200 g"], ["Gelatine", "6.5 g"], ["White chocolate (33%)", "285 g"], ["Cocoa butter", "40 g"]]}, {"type": "steps", "heading": "Method", "items": ["Heat passion and mango purées.", "Pour over the white chocolate and cocoa butter.", "Add gelatine (soaked in water).", "Blend with a hand blender until smooth. Age 1–2 days before using."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Ganache — Raspberry', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Raspberry purée", "400 g"], ["Gelatine", "6.5 g"], ["White chocolate", "285 g"], ["Cocoa butter", "40 g"]]}, {"type": "steps", "heading": "Method", "items": ["Heat the raspberry purée.", "Pour over the chocolate and cocoa butter.", "Add gelatine (soaked in water).", "Blend with a hand blender until smooth. Age 1–2 days."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Ganache — Vanilla', NULL, 'Plated Desserts', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Cream 35%", "440 g"], ["Vanilla pods", "5"], ["Gelatine", "5 g"], ["Dolce (blonde) chocolate", "315 g"], ["Cocoa butter", "43 g"]]}, {"type": "steps", "heading": "Method", "items": ["Heat cream with vanilla.", "Pour hot cream over the chocolate and cocoa butter.", "Add gelatine (soaked in water).", "Blend with a hand blender until smooth. Age 1–2 days."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Baonut (Bao Doughnut)', 'Yield: 1 portion / 150 g', 'Plated Desserts', 'Easy', '1 portion / 150 g', '7 min', '1 hr', NULL, NULL, '[{"type": "list", "heading": "Components", "items": ["Bao doughnut base", "Chocolate glaze", "Salted caramel", "Peanut-caramel crumb", "Raspberries", "Yuzu syrup", "Cocoa crumb", "Edible flowers"]}, {"type": "table", "heading": "Doughnut Dough", "rows": [["Butter", "90 g"], ["Milk", "330 g"], ["Yeast", "40 g"], ["Plain flour", "720 g"], ["Granulated sugar", "70 g"], ["Salt", "pinch"]]}, {"type": "steps", "heading": "Method", "items": ["Melt the butter together with the milk; heat to 41°C (no hotter).", "Add the yeast and stir until dissolved.", "Put all ingredients into a stand mixer, mix with the dough hook.", "Add the yeast mixture and knead for about 5–7 minutes.", "Shape into one large ball (or several smaller ones), cover loosely, and let proof for 1 hour."]}, {"type": "table", "heading": "Chocolate Glaze", "rows": [["Dark chocolate 56%", "200 g"], ["Butter", "30 g"], ["Honey", "40 g"], ["Whole milk", "150 ml"]]}, {"type": "table", "heading": "Salted Caramel", "rows": [["Milk", "100 g"], ["Whipping cream", "300 g"], ["Glucose", "100 g"], ["Sea salt", "2 g"], ["Granulated sugar", "140 g"], ["Glucose", "140 g"], ["Butter", "80 g"]]}, {"type": "text", "text": "Method: Combine milk, cream, the first glucose, and sea salt in a pot; bring to a boil, then remove from heat. Separately caramelize the sugar and second glucose, then whisk in the butter and the hot milk/cream mixture to finish the caramel."}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Cheesecake, Bergamot & Strawberries', 'Plated dessert — serves 8', 'Plated Desserts', 'Hard', 'Serves 8', NULL, '4 hr', NULL, NULL, '[{"type": "table", "heading": "Biscuit Base", "rows": [["Digestive biscuits, crushed", "150 g"], ["Butter, melted", "60 g"], ["Salt", "1 g"]]}, {"type": "table", "heading": "Baked Cheesecake Filling", "rows": [["Cream cheese, room temperature", "400 g"], ["Sugar", "90 g"], ["Eggs", "2"], ["Sour cream", "80 g"], ["Bergamot zest", "1 g"], ["Lemon juice", "10 g"], ["Cornstarch", "10 g"]]}, {"type": "table", "heading": "Bergamot Gel", "rows": [["Bergamot juice (or bergamot-infused orange juice)", "150 g"], ["Sugar", "30 g"], ["Agar agar", "2 g"]]}, {"type": "table", "heading": "Strawberry Compote", "rows": [["Strawberries, quartered", "200 g"], ["Sugar", "40 g"], ["Lemon juice", "10 g"]]}, {"type": "table", "heading": "To Finish", "rows": [["Fresh strawberries, sliced", "80 g"], ["Micro mint or shiso", "to garnish"]]}, {"type": "steps", "heading": "Method", "items": ["Base: mix crushed biscuits, melted butter, and salt. Press into a lined tin or individual rings. Chill to set.", "Filling: beat cream cheese and sugar until smooth. Add eggs one at a time, then sour cream, bergamot zest, lemon juice, and cornstarch — mix just until combined, do not overbeat.", "Pour filling over the chilled base. Bake at 150°C in a water bath until just set with a slight wobble in the centre, about 35–40 minutes. Cool, then chill at least 4 hours.", "Bergamot gel: warm the bergamot juice with sugar. Whisk in agar agar, bring to a boil for 1 minute, then pour into a shallow tray. Chill until set, then blend smooth to a gel.", "Compote: gently cook strawberries with sugar and lemon juice until just broken down but still holding some shape, about 5 minutes. Cool.", "Plate a slice of cheesecake with quenelles or dots of bergamot gel and strawberry compote, fresh strawberry slices, and a scatter of micro herbs."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pecan Pie, Fior di Latte & Caramel', 'Plated dessert — serves 8', 'Plated Desserts', 'Medium', 'Serves 8', NULL, '40 min', NULL, NULL, '[{"type": "table", "heading": "Pecan Pie", "rows": [["Shortcrust pastry shell, blind-baked", "1 (24 cm)"], ["Pecan nuts, halved", "150 g"], ["Eggs", "2"], ["Brown sugar", "100 g"], ["Golden syrup", "120 g"], ["Butter, melted", "40 g"], ["Vanilla extract", "5 g"], ["Salt", "1 g"]]}, {"type": "table", "heading": "Caramel Sauce", "rows": [["Sugar", "150 g"], ["Cream, warmed", "150 g"], ["Butter", "30 g"], ["Salt", "2 g"]]}, {"type": "table", "heading": "Fior di Latte Ice Cream Base", "rows": [["Milk", "500 g"], ["Cream", "200 g"], ["Sugar", "100 g"], ["Milk powder", "30 g"], ["Stabilizer", "3 g"]]}, {"type": "steps", "heading": "Method", "items": ["Pecan pie: whisk eggs, brown sugar, golden syrup, melted butter, vanilla, and salt together. Arrange pecans in the blind-baked shell, pour the filling over.", "Bake at 160°C for 35–40 minutes until just set with a slight wobble in the centre. Cool fully before slicing.", "Caramel: melt sugar in a dry pan over medium heat until deep amber, swirling (not stirring) as needed. Carefully whisk in warmed cream off the heat, then the butter and salt. Cool.", "Fior di latte: warm milk, cream, sugar, and milk powder together with the stabilizer, whisking to dissolve. Chill fully (ideally overnight), then churn in an ice cream machine.", "Plate a slice of pecan pie with a scoop of fior di latte and a generous drizzle of warm caramel sauce."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Mochi Dough (Gyūhei)', NULL, 'Dessert Basics', 'Easy', NULL, '20 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Glutinous (mochiko) rice flour", "100 g"], ["Sugar", "80 g"], ["Water", "150 ml"], ["Cornstarch or potato starch", "for dusting"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk rice flour, sugar, and water together in a microwave-safe bowl until smooth.", "Cover and microwave in 1-minute bursts, stirring vigorously between each, until the mixture turns translucent and stretchy (about 3 minutes total).", "Alternatively, steam the mixture for 15–20 minutes, stirring occasionally.", "Turn out onto a well-dusted surface, dust the top too, and let cool just enough to handle.", "Divide, wrap around fillings (red bean paste, ice cream, fruit), and pinch to seal."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Matcha Custard Base', 'For crème brûlée, pots de crème, or tarts', 'Dessert Basics', 'Medium', NULL, NULL, '35 min', NULL, NULL, '[{"type": "table", "rows": [["Cream", "400 g"], ["Milk", "100 g"], ["Egg yolks", "6"], ["Sugar", "80 g"], ["Matcha powder", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Sift the matcha powder to remove clumps.", "Heat cream and milk together until just below a simmer.", "Whisk egg yolks with sugar until pale, then whisk in the sifted matcha to form a paste before adding liquid.", "Temper the hot cream into the yolk mixture gradually, whisking constantly.", "Strain, then bake in a water bath at 150°C until just set with a slight wobble, about 30–35 minutes.", "Chill fully before serving; torch with sugar on top if making brûlée."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Black Sesame Ice Cream Base', NULL, 'Dessert Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Milk", "500 g"], ["Cream", "200 g"], ["Sugar", "120 g"], ["Egg yolks", "5"], ["Black sesame paste", "80 g"]]}, {"type": "steps", "heading": "Method", "items": ["Heat milk and cream together until just below a simmer.", "Whisk egg yolks with sugar until pale, then whisk in the black sesame paste until smooth.", "Temper the hot milk/cream into the yolk mixture gradually.", "Return to the pot and cook gently, stirring constantly, until the custard coats the back of a spoon (nappe, ~82°C).", "Strain, chill thoroughly (ideally overnight), then churn in an ice cream machine according to manufacturer instructions."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Yuzu Curd', NULL, 'Dessert Basics', 'Easy', NULL, NULL, '10 min', NULL, NULL, '[{"type": "table", "rows": [["Yuzu juice", "80 g"], ["Whole eggs", "2"], ["Egg yolks", "2"], ["Sugar", "100 g"], ["Butter, cubed and cold", "100 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk yuzu juice, whole eggs, egg yolks, and sugar together in a heatproof bowl.", "Set over a pot of gently simmering water (bain-marie) and whisk constantly until thickened, about 8–10 minutes.", "Remove from heat and whisk in the cold butter a few cubes at a time until fully incorporated and glossy.", "Strain through a fine sieve, cover with plastic wrap directly on the surface, and chill."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Coconut Sago Pudding', NULL, 'Dessert Basics', 'Easy', NULL, '15 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Sago pearls", "80 g"], ["Coconut milk", "300 g"], ["Milk", "200 g"], ["Sugar", "60 g"], ["Pandan leaf or vanilla pod (optional)", "1"]]}, {"type": "steps", "heading": "Method", "items": ["Bring a large pot of water to a boil, add sago pearls, and cook, stirring occasionally, until mostly translucent (10–15 minutes).", "Drain and rinse under cold water to stop sticking.", "Warm coconut milk, milk, sugar, and pandan/vanilla together until the sugar dissolves.", "Stir in the cooked sago, simmer a few minutes to marry the flavours, then remove the pandan leaf.", "Chill and serve with fresh mango or other fruit."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Red Bean Paste (Anko)', NULL, 'Dessert Basics', 'Easy', NULL, '1.5 hr', NULL, NULL, NULL, '[{"type": "table", "rows": [["Dried adzuki beans", "200 g"], ["Sugar", "160 g"], ["Pinch of salt", "1 g"]]}, {"type": "steps", "heading": "Method", "items": ["Rinse beans, cover generously with water, and boil for 5 minutes; drain (this removes bitterness).", "Cover with fresh water again and simmer gently, topping up water as needed, until the beans are completely tender (60–90 minutes).", "Drain, reserving a little cooking liquid, then mash or blend to the desired texture (chunky for tsubuan, smooth for koshian).", "Return to the pot with sugar and salt, cook over low heat, stirring, until thick enough to hold its shape on a spoon.", "Cool completely — it will firm up further as it cools."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Dorayaki Pancakes', NULL, 'Dessert Basics', 'Easy', NULL, NULL, '20 min', NULL, NULL, '[{"type": "table", "rows": [["Eggs", "2"], ["Sugar", "60 g"], ["Honey", "20 g"], ["Plain flour", "100 g"], ["Baking powder", "3 g"], ["Water", "20 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk eggs, sugar, and honey together until pale and slightly thickened.", "Sift in flour and baking powder, folding gently to combine.", "Rest the batter 15–20 minutes, then thin slightly with water to a thick pancake consistency.", "Cook small rounds on a lightly oiled non-stick pan over low-medium heat until bubbles form and the surface sets, then flip briefly.", "Cool the pancakes, then sandwich pairs together with red bean paste (anko)."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Mango Sticky Rice', NULL, 'Dessert Basics', 'Easy', NULL, '15 min', '25 min', NULL, NULL, '[{"type": "table", "rows": [["Glutinous rice, soaked overnight", "200 g"], ["Coconut milk", "250 g"], ["Sugar", "50 g"], ["Salt", "2 g"], ["Ripe mango", "2"]]}, {"type": "steps", "heading": "Method", "items": ["Drain the soaked rice and steam over simmering water (lined with muslin) for about 25 minutes until tender and translucent.", "Warm coconut milk with sugar and salt until dissolved; reserve a small amount for drizzling.", "Stir most of the coconut mixture into the hot steamed rice, cover, and let it absorb for 10–15 minutes.", "Slice the mango just before serving.", "Plate the rice with mango alongside, drizzle with the reserved coconut sauce."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Taiyaki Batter', 'Fish-shaped cake, traditionally filled with anko', 'Dessert Basics', 'Easy', NULL, NULL, '15 min', NULL, NULL, '[{"type": "table", "rows": [["Plain flour", "150 g"], ["Baking powder", "5 g"], ["Sugar", "20 g"], ["Egg", "1"], ["Milk", "200 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk egg, sugar, and milk together.", "Sift in flour and baking powder, whisk until smooth with no lumps.", "Rest the batter 15 minutes.", "Heat a taiyaki mould, oil lightly, pour batter into both sides, add a spoonful of red bean paste to one side, then close.", "Cook over medium-low heat, flipping the mould occasionally, until golden and crisp on both sides."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Kinako Dango (Sweet Soy-Bean Rice Dumplings)', NULL, 'Dessert Basics', 'Easy', NULL, NULL, NULL, NULL, NULL, '[{"type": "table", "heading": "Dango", "rows": [["Rice flour (joshinko/shiratamako blend, or mochiko)", "100 g"], ["Water", "80–90 ml"]]}, {"type": "table", "heading": "Kinako Coating", "rows": [["Kinako (roasted soybean flour)", "30 g"], ["Sugar", "20 g"], ["Pinch of salt", "1 g"]]}, {"type": "steps", "heading": "Method", "items": ["Gradually mix water into the rice flour, kneading until it forms a smooth, ear-lobe-soft dough (add water a little at a time).", "Roll into small balls, about 2cm each.", "Drop into boiling water; they''re done once they float to the surface, plus about 1 extra minute.", "Scoop out and plunge into cold water briefly to firm up, then drain well.", "Skewer 3–4 per stick, toss or dust generously with the mixed kinako, sugar, and salt."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Hong Kong-Style Egg Tarts', 'Makes ~12 tarts', 'Dessert Basics', 'Easy', 'Makes 12 tarts', NULL, '30 min', NULL, NULL, '[{"type": "table", "heading": "Pastry", "rows": [["Plain flour", "200 g"], ["Butter, cold and cubed", "100 g"], ["Icing sugar", "30 g"], ["Egg", "1"], ["Cold water", "15 ml"]]}, {"type": "table", "heading": "Egg Custard Filling", "rows": [["Eggs", "3"], ["Sugar", "70 g"], ["Hot water", "120 ml"], ["Evaporated milk", "60 ml"], ["Vanilla extract", "3 g"]]}, {"type": "steps", "heading": "Method", "items": ["Pastry: rub cold butter into flour and icing sugar until sandy. Bind with egg and water into a smooth dough. Chill 30 minutes.", "Roll and line tart moulds, pressing the pastry evenly into the base and sides. Chill again while making the filling.", "Filling: dissolve sugar in hot water, cool slightly, then whisk in eggs, evaporated milk, and vanilla. Strain through a fine sieve for a silky texture.", "Pour the custard into the chilled shells, filling almost to the top.", "Bake at 200°C for 10 minutes, then reduce to 160°C and bake a further 12–15 minutes until the custard is just set with a gentle wobble — avoid browning or bubbling the custard.", "Cool slightly before unmoulding; best served just warm."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Tang Yuan (Black Sesame Rice Balls)', 'Makes ~20 balls', 'Dessert Basics', 'Easy', 'Makes 20 balls', NULL, '15 min', NULL, NULL, '[{"type": "table", "heading": "Dough", "rows": [["Glutinous rice flour", "150 g"], ["Warm water", "120 ml"]]}, {"type": "table", "heading": "Black Sesame Filling", "rows": [["Black sesame seeds, toasted", "80 g"], ["Sugar", "40 g"], ["Butter or lard, softened", "40 g"]]}, {"type": "table", "heading": "Ginger Syrup", "rows": [["Water", "800 ml"], ["Ginger, sliced", "30 g"], ["Rock sugar or brown sugar", "80 g"]]}, {"type": "steps", "heading": "Method", "items": ["Filling: grind toasted sesame seeds to a coarse powder, mix with sugar and softened butter into a paste. Chill until firm enough to roll into small balls (~5g each), then freeze briefly to firm further.", "Dough: gradually mix warm water into the rice flour, kneading to a smooth, soft, ear-lobe-textured dough.", "Divide dough into small pieces, flatten each into a disc, place a frozen sesame ball in the centre, and wrap/seal, rolling smooth between your palms.", "Syrup: simmer water, ginger, and sugar together for 15 minutes to infuse; strain if desired.", "Drop the tang yuan into the simmering ginger syrup (or plain boiling water, then serve in fresh syrup) and cook until they float, plus 2 extra minutes.", "Serve warm in bowls of the ginger syrup."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Pandan Chiffon Cake', 'One 20cm chiffon tin', 'Dessert Basics', 'Easy', NULL, '50 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Egg yolks", "5"], ["Sugar (for yolks)", "50 g"], ["Coconut milk", "80 ml"], ["Vegetable oil", "60 ml"], ["Pandan juice (blended pandan leaves + water, strained)", "40 ml"], ["Plain flour", "120 g"], ["Baking powder", "5 g"], ["Egg whites", "6"], ["Sugar (for whites)", "80 g"], ["Cream of tartar", "2 g"]]}, {"type": "steps", "heading": "Method", "items": ["Whisk egg yolks with the first sugar until pale, then whisk in coconut milk, oil, and pandan juice.", "Sift in flour and baking powder, fold gently to combine into a smooth batter.", "In a separate clean bowl, whip egg whites with cream of tartar until foamy, then gradually add the second sugar, whipping to stiff, glossy peaks.", "Fold one-third of the whipped whites into the yolk batter to loosen it, then gently fold in the rest in two more additions.", "Pour into an ungreased chiffon tin, tap gently to release air bubbles, and bake at 160°C for 45–50 minutes until a skewer comes out clean.", "Invert the tin immediately and cool completely upside down before unmoulding — this keeps the sponge from collapsing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Kulfi (Indian Ice Cream)', 'Serves 6–8', 'Dessert Basics', 'Easy', 'Serves 6–8', '1 hr', '6 hr', NULL, NULL, '[{"type": "table", "rows": [["Whole milk", "1 L"], ["Sweetened condensed milk", "200 g"], ["Cream", "100 g"], ["Cardamom pods, crushed", "4"], ["Pistachios, chopped", "30 g"], ["Saffron strands", "a pinch"]]}, {"type": "steps", "heading": "Method", "items": ["Bring milk to a boil in a heavy-bottomed pot, then reduce to a simmer.", "Simmer, stirring frequently and scraping the sides, until reduced by about half and slightly thickened, 45–60 minutes.", "Stir in condensed milk, cream, crushed cardamom, and saffron, simmer a further 10 minutes.", "Strain out the cardamom pods, stir in chopped pistachios.", "Cool completely, then pour into kulfi moulds or small cups. Freeze at least 6 hours, ideally overnight.", "Dip moulds briefly in warm water to release, then slice and serve immediately."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Gulab Jamun', 'Makes ~20 pieces', 'Dessert Basics', 'Easy', 'Makes 20 pieces', '10 min', '1 hr', NULL, NULL, '[{"type": "table", "heading": "Dough", "rows": [["Milk powder", "100 g"], ["Plain flour", "20 g"], ["Baking powder", "2 g"], ["Butter, melted", "15 g"], ["Milk, as needed to bind", "40–50 ml"]]}, {"type": "table", "heading": "Sugar Syrup", "rows": [["Sugar", "300 g"], ["Water", "300 ml"], ["Cardamom pods, crushed", "3"], ["Rose water", "5 ml"], ["Lemon juice", "5 ml"]]}, {"type": "table", "heading": "For Frying", "rows": [["Ghee or neutral oil", "for deep-frying"]]}, {"type": "steps", "heading": "Method", "items": ["Syrup: dissolve sugar in water with crushed cardamom, simmer 8–10 minutes until lightly syrupy. Stir in rose water and lemon juice (the lemon prevents crystallization). Keep warm.", "Dough: mix milk powder, flour, and baking powder, then work in melted butter and just enough milk to form a soft, slightly sticky dough — do not overwork.", "Roll into smooth balls with no cracks, about 15g each (cracks will split open during frying).", "Heat ghee/oil to 140–150°C (low-medium — too hot will burn the outside before the centre cooks). Fry the balls, moving them gently, until evenly deep golden-brown all over, about 6–8 minutes.", "Drain briefly, then drop the warm, fried balls straight into the warm sugar syrup.", "Let soak at least 1 hour before serving so they plump up and fully absorb the syrup."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Steak Tartare, Classic Preparation', 'Serves 4', 'Salads & Starters', 'Easy', 'Serves 4', NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Beef fillet or sirloin, very fresh, hand-cut", "400 g"], ["Shallot, finely diced", "20 g"], ["Capers, finely chopped", "15 g"], ["Cornichons, finely diced", "20 g"], ["Dijon mustard", "15 g"], ["Egg yolk", "2"], ["Worcestershire sauce", "5 g"], ["Tabasco", "2 g"], ["Chives, chopped", "5 g"], ["Olive oil", "15 g"], ["Salt and black pepper", "to taste"], ["Toasted sourdough, to serve", "4 slices"]]}, {"type": "steps", "heading": "Method", "items": ["Keep the beef very cold throughout — chill the knife and bowl beforehand.", "Hand-chop the beef into fine dice with a sharp knife; do not use a food processor, which crushes the texture and warms the meat.", "Combine the chopped beef with shallot, capers, cornichons, mustard, one egg yolk, Worcestershire sauce, Tabasco, chives, and olive oil.", "Season with salt and pepper, mix gently just until combined.", "Mould into quenelles or rings, top each with the remaining raw egg yolk.", "Serve immediately with toasted sourdough on the side."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Foie Gras Torchon with Sauternes Gelée', 'Serves 8–10', 'Salads & Starters', 'Medium', 'Serves 8–10', '20 min', '12 hr', NULL, NULL, '[{"type": "table", "heading": "Torchon", "rows": [["Foie gras, deveined", "600 g"], ["Salt", "8 g"], ["Sugar", "3 g"], ["White pepper", "2 g"], ["Sauternes or port", "30 g"]]}, {"type": "table", "heading": "Sauternes Gelée", "rows": [["Sauternes wine", "200 ml"], ["Sugar", "20 g"], ["Gelatine leaves", "3"]]}, {"type": "steps", "heading": "Method", "items": ["Devein the foie gras at room temperature, separating the lobes gently by hand to avoid tearing.", "Season with salt, sugar, and white pepper, then drizzle with Sauternes. Marinate refrigerated for 12 hours.", "Roll tightly into a cylinder in cling film, twisting the ends firmly, then wrap again in foil for structure.", "Poach in a water bath at 65°C until the internal temperature reaches 45°C, about 15–20 minutes.", "Chill immediately in ice water, then refrigerate at least 12 hours before slicing.", "Gelée: warm the Sauternes with sugar, dissolve the bloomed gelatine into it, pour into a shallow tray and chill until set. Cut into small cubes.", "Slice the torchon with a hot, clean knife and serve with the Sauternes gelée and toasted brioche."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Escargots de Bourgogne', 'Serves 6 (6 snails per portion)', 'Salads & Starters', 'Easy', 'Serves 6', '10 min', NULL, NULL, NULL, '[{"type": "table", "rows": [["Snails, cooked and shelled", "36"], ["Butter, soft", "250 g"], ["Garlic, finely minced", "25 g"], ["Shallot, finely minced", "15 g"], ["Parsley, finely chopped", "20 g"], ["Pernod or dry white wine", "10 g"], ["Salt", "4 g"], ["Black pepper", "1 g"]]}, {"type": "steps", "heading": "Method", "items": ["Beat the soft butter until light, then mix in garlic, shallot, parsley, Pernod, salt, and pepper until evenly combined.", "Place a small amount of the herb butter in the base of each snail shell (or in the wells of an escargot dish).", "Push a snail into each shell/well, then top generously with more herb butter, sealing the opening.", "Arrange on an escargot tray and bake at 220°C for 8–10 minutes, until the butter is bubbling and lightly golden.", "Serve immediately, very hot, with crusty bread to mop up the butter."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Duck Leg Confit', 'Serves 4 — cure 24 hrs, cook ~3 hrs', 'Meat & Mains', 'Medium', 'Serves 4', '3 hr', '24 hr', NULL, NULL, '[{"type": "table", "rows": [["Duck legs", "4 (~250 g each)"], ["Coarse salt", "40 g"], ["Garlic cloves, crushed", "4"], ["Thyme", "4 sprigs"], ["Bay leaves", "2"], ["Black peppercorns, cracked", "5 g"], ["Duck fat, melted", "1.2 L (enough to submerge)"]]}, {"type": "steps", "heading": "Method", "items": ["Rub the duck legs all over with coarse salt, crushed garlic, thyme, bay leaves, and cracked pepper.", "Cure refrigerated for 24 hours, turning once halfway.", "Rinse off the cure and pat the duck legs completely dry.", "Submerge fully in melted duck fat in a deep ovenproof dish.", "Cook at 140°C for about 3 hours, until the meat is fork-tender and pulls easily from the bone but still holds its shape.", "Cool the legs in the fat; they can be stored submerged, refrigerated, for several weeks.", "To serve: remove from the fat, wipe off excess, and crisp the skin in a hot pan or oven at 220°C for 10–12 minutes."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Roasted Bone Marrow with Herb Gremolata', 'Serves 4', 'Meat & Mains', 'Easy', 'Serves 4', '20 min', '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Beef marrow bones, halved lengthwise", "4 (~15 cm each)"], ["Parsley, finely chopped", "20 g"], ["Garlic, finely minced", "5 g"], ["Lemon zest", "1 lemon"], ["Capers, chopped", "10 g"], ["Olive oil", "15 g"], ["Sea salt", "to taste"], ["Toasted sourdough, to serve", "4 slices"]]}, {"type": "steps", "heading": "Method", "items": ["Soak the halved marrow bones in cold salted water for 2–4 hours to draw out any blood, changing the water once.", "Pat dry, arrange marrow-side up on a roasting tray.", "Roast at 220°C for 15–20 minutes, until the marrow is soft and beginning to turn golden at the edges but not fully melted away.", "Meanwhile combine parsley, garlic, lemon zest, capers, and olive oil for the gremolata; season with a little sea salt.", "Spoon the gremolata generously over the hot marrow bones.", "Serve immediately with toasted sourdough and small spoons for scooping."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Osso Buco alla Milanese', 'Serves 4', 'Meat & Mains', 'Easy', 'Serves 4', '2.5 hr', NULL, NULL, NULL, '[{"type": "table", "heading": "Osso Buco", "rows": [["Veal shanks, cut 4cm thick", "4 (~350 g each)"], ["Flour, for dredging", "60 g"], ["Olive oil", "30 g"], ["Onion, diced", "100 g"], ["Carrot, diced", "100 g"], ["Celery, diced", "100 g"], ["Garlic, minced", "10 g"], ["White wine", "200 ml"], ["Tomato passata", "300 g"], ["Veal or beef stock", "500 ml"], ["Bay leaf", "2"], ["Salt and pepper", "to taste"]]}, {"type": "table", "heading": "Gremolata", "rows": [["Parsley, chopped", "15 g"], ["Lemon zest", "1 lemon"], ["Garlic, minced", "5 g"]]}, {"type": "steps", "heading": "Method", "items": ["Tie a piece of butcher''s twine around each veal shank to hold its shape while cooking.", "Season the shanks and dredge lightly in flour, shaking off excess.", "Sear in olive oil in a heavy pot over high heat until browned on both sides; remove and set aside.", "In the same pot, sauté onion, carrot, celery, and garlic until softened, about 8 minutes.", "Deglaze with white wine, scraping up any browned bits, and simmer until reduced by half.", "Return the shanks to the pot, add tomato passata, stock, and bay leaf — the liquid should come about two-thirds up the shanks.", "Cover and braise at 160°C (or on a very low simmer on the stovetop) for 2–2.5 hours, until the meat is tender and nearly falling from the bone.", "Remove the twine, combine gremolata ingredients and scatter over just before serving, traditionally with saffron risotto."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Cassoulet', 'Serves 8', 'Meat & Mains', 'Medium', 'Serves 8', '2 hr', '45 min', NULL, NULL, '[{"type": "table", "rows": [["White beans (haricot/cannellini), soaked overnight", "500 g"], ["Duck leg confit (see recipe), shredded", "4 legs"], ["Pork belly, cubed", "300 g"], ["Toulouse or garlic sausage, sliced", "300 g"], ["Onion, diced", "150 g"], ["Carrot, diced", "100 g"], ["Garlic, minced", "20 g"], ["Tomato paste", "30 g"], ["Chicken or duck stock", "1.2 L"], ["Bay leaf", "2"], ["Thyme", "3 sprigs"], ["Breadcrumbs, fresh", "80 g"], ["Salt and pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Drain the soaked beans, cover with fresh water, and simmer with a bay leaf until just tender, about 45 minutes; drain and reserve.", "Render the pork belly in a large pot until golden and some fat has rendered out.", "Add onion, carrot, and garlic, sweat until softened.", "Stir in tomato paste, cook 2 minutes, then add the beans, stock, thyme, and remaining bay leaf.", "Layer in the shredded duck confit and sliced sausage.", "Transfer to a large casserole dish, top evenly with fresh breadcrumbs.", "Bake uncovered at 150°C for 1.5–2 hours, until a deep golden crust forms on top — traditionally the crust is broken and pushed back into the cassoulet 2–3 times during baking, forming a new one each time.", "Rest 15 minutes before serving."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'New England-Style Lobster Roll', 'Serves 4', 'Meat & Mains', 'Easy', 'Serves 4', NULL, NULL, NULL, NULL, '[{"type": "table", "rows": [["Lobster meat, cooked and chilled, chopped", "400 g"], ["Mayonnaise", "60 g"], ["Celery, finely diced", "30 g"], ["Lemon juice", "10 g"], ["Chives, chopped", "5 g"], ["Butter, soft", "40 g"], ["Top-split hot dog buns", "4"], ["Salt and pepper", "to taste"]]}, {"type": "steps", "heading": "Method", "items": ["Gently combine the chopped lobster meat with mayonnaise, celery, lemon juice, and chives — mix just enough to bind without crushing the lobster pieces.", "Season with salt and pepper, chill until ready to serve.", "Butter the outer sides of the split buns and toast in a hot pan until golden on both cut sides.", "Fill the toasted buns generously with the chilled lobster mixture.", "Serve immediately with fries or chips."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Burnt Basque Cheesecake', 'One 20cm cake', 'Plated Desserts', 'Easy', NULL, '55 min', '4 hr', NULL, NULL, '[{"type": "table", "rows": [["Cream cheese, room temperature", "900 g"], ["Sugar", "280 g"], ["Eggs", "6"], ["Cream", "350 g"], ["Salt", "3 g"], ["Flour", "25 g"]]}, {"type": "steps", "heading": "Method", "items": ["Line a springform tin generously with parchment paper, letting it overhang well above the sides — the paper wrinkles are part of the traditional look.", "Beat the cream cheese and sugar together until smooth, scraping down the bowl.", "Add eggs one at a time, beating well after each addition.", "Mix in the cream and salt, then fold in the flour just until combined.", "Pour into the lined tin and bake at 220–230°C for 45–55 minutes, until deeply burnished and almost black on top, with a pronounced wobble in the centre — this is correct, not undercooked.", "Cool to room temperature, then chill at least 4 hours before unmoulding and slicing — the centre sets further as it cools."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Classic Vanilla Crème Brûlée', 'Serves 6', 'Plated Desserts', 'Medium', 'Serves 6', NULL, '3 hr', NULL, NULL, '[{"type": "table", "rows": [["Cream", "500 g"], ["Vanilla pod", "1"], ["Egg yolks", "6"], ["Sugar (for custard)", "80 g"], ["Sugar (for brûlée topping)", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Split the vanilla pod and scrape the seeds; warm with the cream until just below a simmer, then let infuse off the heat for 15 minutes.", "Whisk egg yolks with the 80 g sugar until pale.", "Strain the warm cream and gradually whisk it into the yolk mixture.", "Skim any foam, then pour into ramekins.", "Bake in a water bath at 150°C for 30–35 minutes, until just set with a gentle wobble in the centre.", "Cool, then chill at least 3 hours, ideally overnight.", "Just before serving, sprinkle an even layer of sugar over each custard and caramelize with a blowtorch until deep amber and crisp.", "Let the sugar harden for a minute before serving."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Basic White Sandwich Loaf', 'Yield: 1 loaf (900g tin)', 'Bakery & Bread', 'Medium', '1 loaf (900g tin)', '35 min', '1.5 hr', NULL, NULL, '[{"type": "table", "rows": [["Strong white bread flour", "500 g"], ["Instant yeast", "7 g"], ["Salt", "9 g"], ["Sugar", "20 g"], ["Milk, lukewarm", "300 ml"], ["Butter, soft", "30 g"]]}, {"type": "steps", "heading": "Method", "items": ["Combine flour, yeast, salt, and sugar in a mixer bowl (keep salt and yeast on opposite sides when adding, so the salt doesn''t kill the yeast on contact).", "Add the lukewarm milk and butter, mix on low speed until a shaggy dough forms, then knead on medium speed for 8–10 minutes until smooth and elastic.", "Place in a lightly oiled bowl, cover, and proof at room temperature until doubled, about 1–1.5 hours.", "Knock back the dough, shape into a log, and place in a greased 900g loaf tin.", "Cover and proof again until the dough crests just above the rim of the tin, about 45–60 minutes.", "Bake at 200°C for 30–35 minutes, until deep golden and it sounds hollow when tapped on the base.", "Cool on a wire rack for at least 20 minutes before slicing."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'No-Knead Rustic Bread', 'Yield: 1 loaf — minimal hands-on time', 'Bakery & Bread', 'Medium', '1 loaf', '30 min', '18 hr', NULL, NULL, '[{"type": "table", "rows": [["Bread flour", "450 g"], ["Instant yeast", "2 g"], ["Salt", "9 g"], ["Water, room temperature", "375 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Mix flour, yeast, and salt together in a large bowl.", "Add the water and stir with a spoon or spatula just until no dry flour remains — the dough will be shaggy and wet, not smooth. Do not knead.", "Cover and let ferment at room temperature for 12–18 hours, until the surface is covered in bubbles and roughly tripled in size.", "Turn the dough out onto a well-floured surface, fold it over itself a few times, and shape into a round.", "Rest, seam-side down, covered, for 30–45 minutes while the oven preheats.", "Preheat a Dutch oven (with lid) inside the oven at 240°C for at least 30 minutes.", "Carefully transfer the dough into the hot Dutch oven, score the top, cover with the lid, and bake for 30 minutes.", "Remove the lid and bake a further 10–15 minutes until deep golden brown.", "Cool completely on a rack before slicing — the crumb is still setting as it cools."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Simple Focaccia', 'Yield: one 30×20cm tray', 'Bakery & Bread', 'Easy', 'one 30×20cm tray', '25 min', '1.5 hr', NULL, NULL, '[{"type": "table", "rows": [["Bread flour", "500 g"], ["Instant yeast", "7 g"], ["Salt", "12 g"], ["Water, lukewarm", "375 ml"], ["Olive oil, plus extra for the tray", "40 ml"], ["Flaky sea salt, for topping", "to taste"], ["Rosemary sprigs, for topping", "optional"]]}, {"type": "steps", "heading": "Method", "items": ["Mix flour, yeast, and salt together, then add water and olive oil. Mix to a rough, sticky dough — this is meant to be a wet, slack dough.", "Cover and rest 10 minutes, then perform a series of folds (stretch and fold the dough over itself from each side) directly in the bowl. Repeat 3–4 times at 10-minute intervals.", "Cover and proof until roughly doubled, about 1.5 hours.", "Generously oil a baking tray, tip the dough in, and gently stretch it to fill the tray without deflating it too much.", "Cover and rest a further 30–45 minutes.", "Dimple the surface all over with oiled fingertips, drizzle generously with olive oil, and scatter with flaky salt and rosemary if using.", "Bake at 220°C for 20–25 minutes, until deep golden all over.", "Cool slightly on a rack before slicing; best served the same day."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Classic Dinner Rolls', 'Yield: 16 rolls', 'Bakery & Bread', 'Easy', '16 rolls', '22 min', '1 hr', NULL, NULL, '[{"type": "table", "rows": [["Bread flour", "500 g"], ["Instant yeast", "7 g"], ["Sugar", "40 g"], ["Salt", "9 g"], ["Milk, lukewarm", "250 ml"], ["Egg", "1"], ["Butter, soft", "50 g"], ["Egg wash (1 egg + splash of milk)", "1"]]}, {"type": "steps", "heading": "Method", "items": ["Combine flour, yeast, sugar, and salt in a mixer bowl.", "Add milk, egg, and soft butter, mix to a shaggy dough, then knead on medium speed for 8–10 minutes until smooth and elastic.", "Proof covered in a warm place until doubled, about 1 hour.", "Divide into 16 equal pieces (~55g each), shape each into a tight ball by cupping and rolling under your palm.", "Arrange in a greased baking dish, spaced so they touch once proofed.", "Cover and proof again until puffy and touching, about 30–40 minutes.", "Brush with egg wash.", "Bake at 190°C for 18–22 minutes, until deep golden on top.", "Brush with a little extra melted butter as they come out of the oven for a soft, glossy crust."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Basic Pizza Dough', 'Yield: 4 x 250g dough balls', 'Bakery & Bread', 'Medium', '4 x 250g dough balls', '12 min', '72 hr', NULL, NULL, '[{"type": "table", "rows": [["00 flour or strong bread flour", "600 g"], ["Water, room temperature", "390 ml"], ["Instant yeast", "3 g"], ["Salt", "15 g"], ["Olive oil", "15 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Dissolve the yeast in the water, let sit 5 minutes.", "Combine flour and salt in a bowl, add the yeast water and olive oil, mix to a shaggy dough.", "Knead by hand or mixer for 8–10 minutes until smooth and elastic.", "Cover and bulk ferment at room temperature for 2 hours, or refrigerate for 24–72 hours for improved flavour (cold fermentation).", "Divide into 4 pieces (~250g each), shape into tight balls.", "Proof at room temperature for at least 1 hour before stretching (longer if coming straight from the fridge).", "Stretch by hand into a round, leaving a slightly thicker rim for the crust.", "Top as desired and bake at the highest oven temperature possible (ideally 250°C+ or a pizza oven), until the crust is blistered and golden, 5–12 minutes depending on oven."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Sourdough Country Loaf', 'Yield: 1 large loaf — active starter required, ~24 hr total', 'Bakery & Bread', 'Hard', '1 large loaf', '45 min', '14 hr', NULL, NULL, '[{"type": "table", "heading": "Levain", "rows": [["Active sourdough starter", "50 g"], ["Bread flour", "50 g"], ["Water", "50 g"]]}, {"type": "table", "heading": "Final Dough", "rows": [["Bread flour", "450 g"], ["Wholemeal flour", "50 g"], ["Water, room temperature", "375 ml"], ["Levain (above)", "100 g"], ["Salt", "10 g"]]}, {"type": "steps", "heading": "Method", "items": ["Levain: mix starter, flour, and water together the night before, cover, and leave at room temperature until bubbly and doubled, 8–12 hours.", "Autolyse: mix both flours with the water (reserve a small splash), let rest covered for 30–60 minutes before adding anything else.", "Add the levain and mix in thoroughly, rest 30 minutes, then add salt and the reserved water, mixing until fully incorporated.", "Bulk ferment 4–5 hours at room temperature, performing a set of stretch-and-folds every 30 minutes for the first 2 hours, then leaving undisturbed — the dough should grow visibly and feel airy.", "Turn out, shape into a tight round (boule) or oval (bâtard), and place seam-side up in a well-floured proofing basket.", "Cold-proof in the refrigerator for 8–14 hours (overnight) — this develops flavour and makes scoring easier.", "Preheat a Dutch oven inside the oven at 250°C for 45 minutes.", "Turn the cold dough out onto parchment, score the top decisively with a razor or sharp blade.", "Bake covered for 20 minutes, then uncovered at 230°C for a further 20–25 minutes, until deeply browned.", "Cool completely (at least 2 hours) before slicing — the crumb structure is still setting."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Classic Croissants', 'Yield: 12 croissants — laminated dough, ~2 days', 'Bakery & Bread', 'Hard', '12 croissants', '18 min', '3 hr', NULL, NULL, '[{"type": "table", "heading": "Détrempe (Dough)", "rows": [["Bread flour", "500 g"], ["Sugar", "55 g"], ["Salt", "10 g"], ["Instant yeast", "11 g"], ["Milk, cold", "150 ml"], ["Water, cold", "100 ml"], ["Butter, soft (in the dough)", "40 g"]]}, {"type": "table", "heading": "Butter Block", "rows": [["Butter, cold, high-fat (82%+)", "250 g"]]}, {"type": "table", "heading": "To Finish", "rows": [["Egg wash (1 egg + splash of milk)", "1"]]}, {"type": "steps", "heading": "Method", "items": ["Détrempe: combine flour, sugar, salt, and yeast. Add milk, water, and soft butter, mix to a smooth dough, about 5–6 minutes. Do not overwork — this dough needs minimal gluten development compared to bread.", "Shape into a rough rectangle, wrap, and chill at least 2 hours or overnight.", "Butter block: pound the cold butter between parchment into a 20×20cm square, keeping it cold and pliable.", "Roll the détrempe into a rectangle roughly double the size of the butter block, place the butter in the centre, and fold the dough over to fully encase it (like a book).", "Roll out into a long rectangle and perform a single fold (fold one-third over, then the other third over that, like a letter). Wrap and chill 30–45 minutes.", "Repeat the roll-and-fold two more times (three single folds total), chilling between each — keep the dough cold throughout to maintain distinct butter layers.", "After the final fold and rest, roll the dough out to about 4mm thickness, trim the edges square.", "Cut into triangles (about 10cm base, 25cm tall), gently stretch each slightly, and roll up from the base to the tip.", "Curve into a crescent shape, place on trays with space to expand.", "Proof at a warm room temperature (not hot, or the butter will melt) until visibly puffy and jiggly, 2–3 hours.", "Brush with egg wash and bake at 200°C for 15–18 minutes, until deep golden and the layers are visibly flaky."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'French Baguette', 'Yield: 3 baguettes — poolish preferment, ~18 hr total', 'Bakery & Bread', 'Hard', '3 baguettes', '15 min', '16 hr', NULL, NULL, '[{"type": "table", "heading": "Poolish (Preferment)", "rows": [["Bread flour", "150 g"], ["Water, room temperature", "150 ml"], ["Instant yeast", "0.5 g"]]}, {"type": "table", "heading": "Final Dough", "rows": [["Bread flour", "350 g"], ["Water, room temperature", "175 ml"], ["Salt", "10 g"], ["Instant yeast", "2 g"], ["Poolish (above)", "all"]]}, {"type": "steps", "heading": "Method", "items": ["Poolish: mix flour, water, and yeast together the night before, cover, and leave at room temperature for 12–16 hours until domed and bubbly.", "Combine the poolish with the remaining flour, water, salt, and yeast; mix to a smooth, elastic dough, about 8 minutes.", "Bulk ferment 2 hours at room temperature, folding once at the halfway point.", "Divide into 3 pieces, pre-shape into loose logs, rest 20 minutes covered.", "Shape each into a tight baguette by folding and rolling, tapering the ends.", "Proof seam-side up on a floured couche (or floured cloth) for 45–60 minutes.", "Preheat the oven to 250°C with a steam tray or water spray setup.", "Turn the baguettes onto a baking sheet, score with 4–5 confident diagonal slashes.", "Bake with steam for the first 10 minutes, then remove steam and continue baking at 230°C for 12–15 minutes, until deeply golden and crisp.", "Cool on a rack for at least 20 minutes — the crust continues to crackle as it cools."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Panettone', 'Yield: one 1kg panettone — enriched, multi-stage, ~2 days', 'Bakery & Bread', 'Medium', 'one 1kg panettone', '55 min', '12 hr', NULL, NULL, '[{"type": "table", "heading": "Day 1 — First Dough", "rows": [["Active sourdough starter (stiff)", "100 g"], ["Bread flour", "200 g"], ["Sugar", "60 g"], ["Egg yolks", "3"], ["Butter, soft", "80 g"], ["Water, lukewarm", "80 ml"]]}, {"type": "table", "heading": "Day 2 — Final Dough", "rows": [["Bread flour", "80 g"], ["Sugar", "60 g"], ["Honey", "20 g"], ["Egg yolks", "3"], ["Butter, soft", "80 g"], ["Salt", "5 g"], ["Vanilla pod, seeds only", "1"], ["Orange zest", "1 orange"], ["Candied orange peel", "80 g"], ["Raisins, soaked in warm water and drained", "80 g"]]}, {"type": "steps", "heading": "Method", "items": ["Day 1: mix the stiff starter with flour, sugar, egg yolks, and water into a smooth dough. Work in the soft butter gradually until fully incorporated and the dough is glossy and elastic.", "Proof in a warm place until roughly tripled, 10–12 hours (can take longer depending on starter activity — the dough must at least triple for the final structure to work).", "Day 2: mix the risen first dough with flour, sugar, honey, egg yolks, salt, vanilla, and orange zest until smooth and elastic.", "Gradually incorporate the soft butter in stages, kneading until each addition is fully absorbed before adding more (this dough is very rich and takes patience).", "Gently fold in the candied peel and drained raisins.", "Shape into a ball and place in a panettone paper mould.", "Proof until the dough reaches close to the top of the mould, 6–8 hours in a warm place.", "Score a cross on top and place a small piece of butter in the centre if desired.", "Bake at 170°C for 45–55 minutes, until a skewer comes out clean and internal temperature reaches 90–92°C — tent with foil if the top browns too quickly.", "Immediately upon removing from the oven, skewer the base and hang the panettone upside down for at least 4 hours (this prevents the structure from collapsing as it cools).", "Once fully cooled, store wrapped at room temperature."]}]'::jsonb, false);
insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Chocolate Babka', 'Yield: 2 loaves — enriched, laminated-style filling', 'Bakery & Bread', 'Hard', '2 loaves', '35 min', '2 hr', NULL, NULL, '[{"type": "table", "heading": "Dough", "rows": [["Bread flour", "500 g"], ["Sugar", "80 g"], ["Salt", "8 g"], ["Instant yeast", "8 g"], ["Milk, lukewarm", "180 ml"], ["Eggs", "2"], ["Butter, soft", "120 g"]]}, {"type": "table", "heading": "Chocolate Filling", "rows": [["Dark chocolate, melted", "200 g"], ["Butter, soft", "80 g"], ["Cocoa powder", "30 g"], ["Icing sugar", "60 g"]]}, {"type": "table", "heading": "Sugar Syrup (to finish)", "rows": [["Sugar", "50 g"], ["Water", "50 ml"]]}, {"type": "steps", "heading": "Method", "items": ["Dough: combine flour, sugar, salt, and yeast. Add milk and eggs, mix to a shaggy dough, then work in the soft butter gradually until fully incorporated.", "Knead until smooth, glossy, and elastic, about 10–12 minutes — this enriched dough takes longer to develop than a lean bread dough.", "Proof covered until doubled, about 1.5–2 hours.", "Filling: beat melted chocolate, soft butter, cocoa powder, and icing sugar together into a smooth, spreadable paste.", "Divide the dough in half. Roll each half into a large rectangle, spread evenly with half the chocolate filling.", "Roll up tightly from the long edge into a log.", "Slice the log lengthwise down the middle, exposing the layers, then twist the two halves around each other, keeping the cut sides facing up.", "Place each twisted loaf into a greased loaf tin, tucking the ends under.", "Proof covered until puffy, about 45–60 minutes.", "Bake at 180°C for 30–35 minutes, tenting with foil if browning too quickly.", "Simmer sugar and water together until dissolved; brush the hot syrup over the babka as soon as it comes out of the oven for a glossy finish.", "Cool in the tin for 15 minutes before turning out."]}]'::jsonb, false);
